function shuffleArray(array) {
    var currentIndex = array.length, temporaryValue, randomIndex;
  
    // While there remain elements to shuffle
    while (0 !== currentIndex) {
        // Pick a remaining element
        randomIndex = Math.floor(Math.random() * currentIndex);
        currentIndex -= 1;
  
        // Swap it with the current element
        temporaryValue = array[currentIndex];
        array[currentIndex] = array[randomIndex];
        array[randomIndex] = temporaryValue;
    }
  
    return array;
}

function sqb_externale_copy_to_clipboard(obj) {
	
	jQuery(obj).text('Copied');
	//jQuery('#embedCodeModal').modal('hide')
	var elementId = jQuery(obj).attr("data-id");
	var aux = document.createElement("input");
	var externalScript = jQuery('#dynamic_copyable_text_sqb_cg').text();
	aux.setAttribute("value", externalScript);
	document.body.appendChild(aux);
	aux.select();
	document.execCommand("copy"); 
	document.body.removeChild(aux);

	setTimeout(function() {
		jQuery(obj).text("Copy");
	}, 2000);
}

function splitRange(total, splits) {
	const rangeSize = Math.floor(total / splits);
	const remainder = total % splits;
	const result = [];
  
	let start = 0;
	let end = rangeSize - 1;
  
	for (let i = 0; i < splits; i++) {
	  if (i < splits - 1) {
		end += (i < remainder) ? 1 : 0;
	  } else {
		end = total - 1;
	  }
  
	  result.push({ min: start, max: end });
  
	  start = end + 1;
	  end = start + rangeSize - 1;
	}
  
	return result;
  }

