function sqb_chatgpt_pdf_download(){

	var otext = jQuery('.chatgpt_download_pdf ').text();
	jQuery('.chatgpt_download_pdf ').text('Please wait...');
	jQuery.ajax({
		type: "POST",
		url: ajaxurl+'?action=sqb_ai_generate_quiz_pdf',
		data: sqbchatGpt,
		xhrFields: {
			responseType: 'blob'
		},
		success: function(blob, status, xhr) {
		
			jQuery('.chatgpt_download_pdf').text(otext);
			var filename = "";
			var disposition = xhr.getResponseHeader('Content-Disposition');
			if (disposition && disposition.indexOf('attachment') !== -1) {
				var filenameRegex = /filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/;
				var matches = filenameRegex.exec(disposition);
				if (matches != null && matches[1]) filename = matches[1].replace(/['"]/g, '');
			}

			if (typeof window.navigator.msSaveBlob !== 'undefined') {
				window.navigator.msSaveBlob(blob, filename);
			} else {
				var URL = window.URL || window.webkitURL;
				var downloadUrl = URL.createObjectURL(blob);
				if (filename) {
					var a = document.createElement("a");
					if (typeof a.download === 'undefined') {
						window.location.href = downloadUrl;
					} else {
						a.href = downloadUrl;
						a.download = filename;
						document.body.appendChild(a);
						a.click();
					}
				} else {
					window.location.href = downloadUrl;
				}
				setTimeout(function () { URL.revokeObjectURL(downloadUrl); }, 100);
			}
		},error: function(XMLHttpRequest, textStatus, errorThrown) { 
			
		} 
	});
}

