	var sqb_mediauploader;
    function initAndOpenMediaUploader(button) {
        var data = jQuery(button);
        window.sqb_img_class = data.attr('data-class');

        if (sqb_mediauploader) {
            sqb_mediauploader.open();
            return;
        }

        sqb_mediauploader = wp.media.frames.file_frame = wp.media({
            title: 'Choose Image',
            button: {
                text: 'Choose Image'
            },
            multiple: false
        });

        sqb_mediauploader.on('select', function() {
            var attachment = sqb_mediauploader.state().get('selection').first().toJSON();
            jQuery('#sqb-email-template-logo-inner .sqbimagefield-img').attr('src', attachment.url);
            jQuery('#sqb-email-template-logo-inner .sqb-default-upload-wrapper').removeClass('active');
            jQuery('#sqb-email-template-logo-inner .sqb-default-upload-wrapper-has-img').addClass('active');
            jQuery('#sqb-email-template-logo-inner .quiz-emailtemp-preview-img img').attr('src', attachment.url);
            jQuery('#sqb-email-template-logo-file').val(attachment.url);
            // Commented out as in the original code
            // jQuery(data).parent().find('.sqb_img_draggable').attr('alt', attachment.alt);
        });

        sqb_mediauploader.open();
    }

    jQuery(document).on('click', '.sqbimagefield-upload-btn', function(e) {
        e.preventDefault();
        initAndOpenMediaUploader(this);
    });

    // Event handler for replace logo button
    jQuery(document).on('click', '.replace-logo-btn', function(e) {
        e.preventDefault();
        var uploadBtn = jQuery('.sqbimagefield-upload-btn')[0];
        initAndOpenMediaUploader(uploadBtn);
    });

