	jQuery('input[name="form_view_option"]').on('change', function(){
		var get_val = jQuery(this).val();
		var get_template = jQuery('input[name="select_temp"]:checked').val();
		if(get_val == 'horizontal' || get_val == "vertical" || get_val == "just_button"){
			var optin_template = 'template1';
		}else{
			var optin_template = 'justEmail';
		}

		SQBShowLoader();
		jQuery.post(ajaxurl, 
		{
			action: 'sqb_load_optin_template',
			optin_template : optin_template
		}, function(response) {
			SQBHideLoader();
			var result = jQuery.parseJSON(response);
			if(result){
				jQuery('.sqb-redirect-url-main-div').hide();
				if(get_val == 'horizontal' || get_val == "vertical" || get_val == 'just_button'){
					jQuery('.optin_template_html_preview_outer').html(result);

					jQuery('#sqb_direct_signup').addClass('fields_reorder_enabled');
					jQuery('.form_cls').sortable();
					if(get_val == 'horizontal'){
						jQuery('.optin_template_html_preview_outer .Quiz-Optin-Template').addClass('form_view_horizontal');
					}
					jQuery('.opt_custom_fields_list_wrapper').show();
					jQuery('.first_name_option').show();
					jQuery('.optin_template_html_preview_outer .Quiz-Optin-Template').removeClass('form_view_justemail');
					jQuery('.optin-screen-buttons').show();

					if(get_val == 'just_button'){
						jQuery('.text_privacy_policy').hide();
						jQuery('#elfirst_name').hide();
						jQuery('#elemail').hide();
						jQuery('.optin_template_html_preview_outer .Quiz-Optin-Template').addClass('form_view_justbutton');
						jQuery('.sqb-redirect-url-main-div').show();
						jQuery('#startshowHide_image_optin').prop('checked',true).trigger('change');
					}
				}else{
					jQuery('#sqb_direct_signup').removeClass('fields_reorder_enabled');
					jQuery('.form_cls').sortable("destroy");
					jQuery('.optin-screen-buttons').hide();
					jQuery('.optin_template_html_preview_outer .Quiz-Optin-Template').removeClass('form_view_horizontal');
					jQuery('.optin_template_html_preview_outer .Quiz-Optin-Template').addClass('form_view_justemail');
					jQuery('.optin_template_html_preview_outer .continue_btn').remove();
					jQuery('.optin_template_html_preview_outer .form_cls').html(result);
					jQuery('.opt_custom_fields_list_wrapper').hide();
					jQuery('.first_name_option').hide();
				}

				

				if(get_template == "template8"){
					jQuery('.Quiz-Optin-Template').addClass('outer-style8');
				}else if(get_template == "template7"){
					jQuery('.Quiz-Optin-Template').addClass('outer-style7');
				}else if(get_template == "template6"){
					jQuery('.Quiz-Optin-Template').addClass('remove-border');
				}else if(get_template == "template2"){
					jQuery('.Quiz-Optin-Template').addClass('outer-style1');
				}else if(get_template == "template3"){
					jQuery('.Quiz-Optin-Template').addClass('outer-style2');
				}else if(get_template == "template4"){

					if(get_val != 'just_email'){
						jQuery( "#Opt-Screen-Settings .optin_template_html_preview_outer .quiz_comon_template" ).wrap( "<div class='outer-style3'></div>" );
						jQuery( ".optin_template_html_preview_outer .outer-style3" ).prepend("<span class='outer_style3_span_first'></span><span class='outer_style3_span_second'></span>");
					}
					
				}
			}

			sqb_tiny_mce_editor();
		});
	});

