	jQuery(document).on('click','.chatgpt-sh-prompt',function(){
		var type = jQuery(this).attr('data-type');
		var screen = jQuery(this).closest('.chatgpt-screen').attr('data-screen');
		sqbchatGpt['quiz_type'] = jQuery('input[name="chatgpt_quiz_ntype"]:checked').val();

		if(sqbchatGpt['quiz_type'] == 'survey'){
			jQuery('.chatgpt-error-field').hide();
			if (jQuery('input[name="survey_type"]:checked').length < 1) {
				jQuery('.survey-type-wrapper .chatgpt-error-field').show();
				return false;
			}

			if (jQuery('input[name="survey_type"]:checked').length > 0 && jQuery('#chatgpt_survay_goal').val() == '') {
				jQuery('.survey-goal-wrapper .chatgpt-error-field').show();
				return false;
			}

			if (jQuery('#chatgpt_survaycontent').val() == '') {
				jQuery('.survey-describe .chatgpt-error-field').show();
				return false;
			}
		}

		if(type =='prompt'){
			jQuery('.chatgpt-prompt').show();
			jQuery('.chatgpt-normal').hide();
			jQuery('#chatgpt_title_prompt').trigger('change');
			var topic_name = jQuery('#chatgpt_title').val();
			var quiz_lang = jQuery('#chatgpt_quiz_nlang').val();
			if(sqbchatGpt['quiz_type'] == 'scoring'){
				var tmprompt_html = chatgpt_mprompt_s.replaceAll('%%LANG_MSG%%','\n\nResponse in '+quiz_lang+'');
			}else if(sqbchatGpt['quiz_type'] == 'survey'){
				var chatgpt_msurvaycontent = jQuery('#chatgpt_survaycontent').val();
				var tmprompt_html = chatgpt_mprompt_survey.replaceAll('%%LANG_MSG%%','\n\nResponse in '+quiz_lang+'');
				tmprompt_html = tmprompt_html.replaceAll('%%PRODUCT_DETAIL%%',chatgpt_msurvaycontent);
			}else{
				var tmprompt_html = chatgpt_mprompt_p.replaceAll('%%LANG_MSG%%','\n\nResponse in '+quiz_lang+'');
			}
			if(sqbchatGpt['quiz_type'] == 'survey'){
				var chatgpt_survay_goal = jQuery('#chatgpt_survay_goal').val();
				tmprompt_html = tmprompt_html.replaceAll('[topic]',chatgpt_survay_goal);
			}else{
				topic_name = jQuery('#chatgpt_goal').val();
				tmprompt_html = tmprompt_html.replaceAll('[topic]',topic_name);
			}
			jQuery('#chatgpt_'+screen+'_prompt').val(tmprompt_html);
			
			if(jQuery('input[name="chatgpt_quiz_ntype"]:checked').val() != 'survey'){
				jQuery('.nquiztopicwap').hide();
			}

		}else{

			jQuery('.chatgpt-normal').show();
			jQuery('.chatgpt-prompt').hide();
			
			if(sqbchatGpt['quiz_type'] == 'survey'){
				jQuery('.ai-hide-this-if-type-survay').hide();
				jQuery('.ai-show-this-if-type-survay').show();
			}else{
				jQuery('.ai-hide-this-if-type-survay').show();
				jQuery('.ai-show-this-if-type-survay').hide();
			}
			if(jQuery('input[name="chatgpt_quiz_ntype"]:checked').val() != 'survey'){
				jQuery('.nquiztopicwap').hide();
			}else{
				jQuery('.nquiztopicwap').show();
			}
			
		}

		//if(jQuery('#chatgpt_'+screen+'_prompt').val() == ''){
			
		//}
		jQuery('.chatgpt_'+screen+'_prompt_type').val(type);
		
	});
	
	jQuery(document).on('click','.chatgpt_back',function(){
		
		var old_screen_div = jQuery(this).closest('.chatgpt-screen');
		var new_screen = jQuery(this).attr('data-screen');
		
		var old_screen = old_screen_div.attr('data-screen');
		var new_screen_div = jQuery('.chatgpt-quiz-'+new_screen+'-screen');
		
		var databack = jQuery(this).attr('data-back');
		var alert = jQuery(this).attr('data-alert');

		if( alert == "1" && (new_screen == 'questions' || new_screen == 'outcome')){
			var msg = '';
			if(new_screen == 'questions'){
				msg = "Please note: If you use the back button, you'll lose the questions.";
			}else{
				msg = "Please note: If you use the back button, you'll lose the outcomes.";
			}

			swal({
				text: msg,
				//type: "warning",
				showCancelButton: true,
				showCloseButton: true,
				confirmButtonColor: "#DD6B55",
				confirmButtonText: "Ok",
				customClass: '',
				
			}).then((result) => {
				if (result.value) {
					old_screen_div.hide();
					old_screen_div.find('.chatgpt_form').show();
					old_screen_div.find('.chatgot-quiz-'+old_screen+'-response-main').hide();
					//old_screen_div.find('.chagpt-quiz-'+old_screen+'-response').html('');

					
					new_screen_div.show();
					if(databack == '1'){
						
					}else{
						new_screen_div.find('.chatgpt_form').show();
						new_screen_div.find('.chatgot-quiz-'+new_screen+'-response-main').hide();
						//new_screen_div.find('.chagpt-quiz-'+new_screen+'-response').html('');
					}

					if(new_screen == 'outcome'){
						jQuery('#chatgpt-quiz-outcome-screen .chatgpt-section-heading-1').show();
					}
					
					chatgpt_scrollto();
				}
			});

		}else{

			if(new_screen == 'selection'){
				resetChatGPT(true);
			}

			old_screen_div.hide();
			old_screen_div.find('.chatgpt_form').show();
			old_screen_div.find('.chatgot-quiz-'+old_screen+'-response-main').hide();
			//old_screen_div.find('.chagpt-quiz-'+old_screen+'-response').html('');

			
			new_screen_div.show();
			if(databack == '1'){
				
			}else{
				new_screen_div.find('.chatgpt_form').show();
				new_screen_div.find('.chatgot-quiz-'+new_screen+'-response-main').hide();
				//new_screen_div.find('.chagpt-quiz-'+new_screen+'-response').html('');
			}
			
			if(new_screen == 'outcome'){
				jQuery('#chatgpt-quiz-outcome-screen .chatgpt-section-heading-1').show();
			}

			chatgpt_scrollto();
		}

		
	});

