	jQuery(document).on('click','.chatgpt_generate_responsce_popup', function(){

		jQuery('.chatgpt_generate_mquestion_error_popup').hide();
		try {

			var jsonText = jQuery('#chatgpt_question_json_popup').val();
			var json = JSON.parse(jsonText);
			var i = 1;
			jQuery.each(json, function(index, question) {

				if(question.question == undefined || question.type == undefined || question.answers == undefined){
					return true;
				}
				
				var type = '';
				if(question.type == 'single'){
                    type = 'Single';
                    typslug = 'single';
                }else if(question.type == 'multiple'){
                    type = 'Multiple';
                    typslug = 'multi';
                }else if(question.type == 'open'){
                    type = 'Open';
                    typslug = 'text';
                }

				if(type == ''){
					return true;
				}

				json[index]['type'] = typslug;

				i++;
				var ans_html = '';
				jQuery.each(question.answers, function(index, answer) {
					if(answer.answer != undefined && answer.answer != ''){
						ans_html += '<div class="sqb-cg-qa-item">'+answer.answer+'</div>';
					}
				});

				heading = '';
				if(question.length > 0){
					heading = '<div class="sqb-cg-qa-lbl">Answers :</div>';
				}

				var res_html = '<li><input class="quiz_checkbox" name="chatgpt_question_list[]" type="checkbox" value="1"><div class="chagpt-single_quiz_card"><div class="sqb-gpt-qt-wrapper"><div class="sqb-gpt-qt-lbl">'+type+'</div></div><div class="sqb-cg-question">'+question.question+' <i>('+type+')</i></div><div class="sqb-cg-qa">'+heading+' <div class="sqb-cg-qa-data">'+ans_html+'</div></div></div></li>';

				jQuery('.chagpt-quiz-questionslist-mresponse ul').append(res_html);
				
				sqbchatGpt['questions'].push(question);
			});


			jQuery('#show_only_selected_questionlist').prop('checked',false);
			jQuery('.gpt-quiz-form-side-popup').removeClass('active_Side_Popup');
			
		} catch (error) {
			jQuery('.chatgpt_generate_mquestion_error_popup').show();
		}

	});

