	jQuery(document).on('click','.chatgpt_to_outcome_screen',function(){
		var quiz_title = jQuery('#chatgpt_selected_topic').val();

		var i = 0;
		sqbchatGpt['sel_questions'] = [];
		jQuery('input[name="chatgpt_question_list[]"]').each(function (index) {
			if (this.checked) {
				sqbchatGpt['sel_questions'][i] = sqbchatGpt['questions'][index];
				i++;
			}
		});

		if(sqbchatGpt['sel_questions'][0] == undefined){
			sqb_sweet_message('','Please select at least one question',"");
			return false;
		}

		if(sqbchatGpt['sel_questions'].length > 25){
			sqb_sweet_message('',"Sorry, can't add more than 25 questions.","");
			return false;
		}
		

		jQuery('.chatgpt-quiz-createquiz-screen').show();
		jQuery('.chatgpt-quiz-questions-screen').hide();
		jQuery('.chatgpt-topic').html(quiz_title);

		if(sqbchatGpt['quiz_type'] == 'scoring'){

			var questions = sqbchatGpt['sel_questions'];
			var outcomes = sqbchatGpt['sel_outcomes'];
			var outcomes_order = sqbchatGpt['outcomes_order'];

			var max_points = 0;
			
			jQuery.each(questions, function(i, question) {

				jQuery.each(question['answers'], function(j, answer) {

					if(jQuery.isNumeric(answer['points']) && answer['correct'] == 'true'){
    					var points = parseInt(answer['points']);
                    }else{
                        var points = 0;
                    }
					max_points = max_points + points;

				});
			});

			var ranges = splitRange(max_points, outcomes.length);

			var new_outcomes_order = {};
			var k = 1;
			jQuery.each(outcomes_order, function(i, o) {
				new_outcomes_order[o.outcome_title] = k;
				k++;
			});

			outcomes.sort(function(a, b) {
				return new_outcomes_order[a.title] - new_outcomes_order[b.title];
			  });

			sqbchatGpt['sel_outcomes'] = outcomes;
			jQuery.each(outcomes, function(i, outcome) {
				sqbchatGpt['sel_outcomes'][i]['range'] = ranges[i];
			});

			var outcome_len = outcomes.length;
			sqbchatGpt['sel_outcomes'][outcome_len-1]['range']['max'] = max_points;
		}
		chatgpt_scrollto();
	});

