	jQuery(document).on('click','.chatgpt_generate_quiz_mquestions_prompt2', function(){

		var question_single_limit = jQuery('#chatgpt_mquestion_single_limit').val();
		var question_multi_limit = jQuery('#chatgpt_mquestion_multi_limit').val();
		var question_open_limit = jQuery('#chatgpt_mquestion_open_limit').val();
		var question_ratingscale = jQuery('#chatgpt_mquestion_ratingscale_limit').val();

		if (jQuery('input[name=chatgpt_quiz_type]:checked').val() == 'survey') {
			var chatgpt_question_additional = jQuery('#chatgpt_msurvay_goal').val();
		} else{
			var chatgpt_question_additional = jQuery('#chatgpt_mquestion_additional').val();
		}
		

		if(question_single_limit == ''){
			question_single_limit = 0;
		}

		if(question_multi_limit == ''){
			question_multi_limit = 0;
		}

		if(question_open_limit == ''){
			question_open_limit = 0;
		}

		if(question_ratingscale == ''){
			question_ratingscale = 0;
		}

		var total_questions = parseInt(question_single_limit) + parseInt(question_multi_limit) + parseInt(question_open_limit) + parseInt(question_ratingscale);

		if(total_questions < 1){
			sqb_sweet_message('',"Min limit is 1","");
			return false;
		}

		if(total_questions > 15){
			sqb_sweet_message('',"Max Limit is 15.","");
			return false;
		}

		if(chatgpt_question_additional == ''){
			sqb_sweet_message('',"Please enter the goal","");
			return false;
		}

		jQuery('.chatgpt-quiz-questions-mscreen').hide();
		jQuery('.chatgpt-quiz-questionsprompt-mscreen').show();
	});


	jQuery(document).on('click','.chatgpt_generate_mquestion_list', function(){

		jQuery('.chatgpt_generate_mquestion_error').hide();
		var jsonText = jQuery('#chatgpt_question_json').val();

		try {

			var json = JSON.parse(jsonText);

			jQuery('.chagpt-quiz-questionslist-mresponse').html('');
			jQuery('.chagpt-quiz-questionslist-mresponse').append('<ul></ul>');
			var ci = 1;

			if(sqbchatGpt['quiz_type'] == 'scoring'){
				var questions = json['questions'];
			}else{
				var questions = json;
			}

			jQuery.each(questions, function(i, question) {

				if(question.question == undefined || question.type == undefined || question.answers == undefined){
					return true;
				}

				var type = '';
				if(question.type == 'single'){
                    type = 'Single';
                    typslug = 'single';
                }else if(question.type == 'multiple'){
                    type = 'Multiple';
                    typslug = 'multi';
                }else if(question.type == 'open'){
                    type = 'Open';
                    typslug = 'text';
				}else if(question.type == 'rating'){
                    type = 'Rating Scale';
                    typslug = 'rating';
                }

				if(type == ''){
					return true;
				}

				if(sqbchatGpt['quiz_type'] == 'scoring'){
					json['questions'][i]['type'] = typslug;
				}else{
					json[i]['type'] = typslug;
				}

				ci++;
				var ans_html = '';

				if(question.answers.length > 0 && typslug != 'rating'){
					question.answers = shuffleArray(question.answers);
				}

				jQuery.each(question.answers, function(index, answer) {
					if(answer.answer != undefined && answer.answer != ''){
						ans_html += '<div class="sqb-cg-qa-item">'+answer.answer+'</div>';
					}
				});

				heading = '';
				if(question.length > 0){
					heading = '<div class="sqb-cg-qa-lbl">Answers :</div>';
				}

				var res_html = '<li><input class="quiz_checkbox" name="chatgpt_question_list[]" type="checkbox" value="1"><div class="chagpt-single_quiz_card"><div class="sqb-gpt-qt-wrapper"><div class="sqb-gpt-qt-lbl">'+type+'</div></div> <div class="sqb-cg-question">'+question.question+' <i>('+type+')</i></div><div class="sqb-cg-qa">'+heading+'<div class="sqb-cg-qa-data">'+ans_html+'</div></div></div></li>';

				jQuery('.chagpt-quiz-questionslist-mresponse ul').append(res_html);

				if(sqbchatGpt['questions'] == undefined){
					sqbchatGpt['questions'] = [];
				}
				
				sqbchatGpt['questions'].push(question);
				
			});

			if(sqbchatGpt['questions'] == undefined){
				sqbchatGpt['questions'] = [];
			}

			if(sqbchatGpt['questions'].length < 1){
				sqb_sweet_message('','We noticed that ChatGPT has not given back response in the right format. It sometimes does that. Please copy the code from SQB again, use a new chat window in ChatGPT and enter the code.','');
				jQuery('.chatgpt-quiz-questions-response-mscreen').show();
				jQuery('.chatgpt-quiz-questionsprompt-mscreen').show();
				return false;
			}
			if(sqbchatGpt['quiz_type'] == 'scoring'){
				sqbchatGpt['outcomes_order'] = json['outcomes'];
			}
			jQuery('.chatgpt-quiz-questionslist-mscreen').show();
			jQuery('.chatgpt-quiz-questions-response-mscreen').hide();
			jQuery('.chatgot-quiz-questionslist-response-main').show();

		} catch (error) {
			//sqb_sweet_message('','Invalid','');
			jQuery('.chatgpt_generate_mquestion_error').show();
		}

	});

