	jQuery('#caption-upload-button').click(function() {
		
		if(jQuery('#caption-file-input').val() == ''){
			swal('Please select a file');
			return false;
		}
		
		// Get the file input element and the form element
		var fileInput = jQuery('#caption-file-input')[0];
		var formData = new FormData(jQuery('#upload-caption-form')[0]);


		swal({
			title: "Upload Captions (.vtt) File ?",
			text: "This will replace all the captions you already have for this video.",
			showCancelButton: true,
			showCloseButton: true,
			confirmButtonColor: "#DD6B55",
			confirmButtonText: "Yes",
			customClass: 'upload-caption-popup',
			
		}).then((result) => {
			if (result.value) {
				jQuery('.sqb_loading_wrapper').show();
				jQuery.ajax({
					url: ajaxurl+'?action=getCaptionfromFile',
					type: 'POST',
					data: formData,
					contentType: false,
					processData: false,
					success: function(response) {
						jQuery('.video-caption-bottom-wrapper').show();
						jQuery('.sqb_loading_wrapper').hide();
						response = JSON.parse(response);	
						if(response.output){
							jQuery('#upload-caption-form')[0].reset();
							jQuery('.sqb-capt-upload-sf').text('');
							jQuery('.caption_wrapper_outer').html(response.output);
							jQuery('.caption_upload_wrapper_outer').hide();
							jQuery('.caption_manual_outer').show();
						}else{
							swal('Invalid content in the file');
						}
					}
				});
			}
		});
	  });


