	jQuery(document).on('click','.sqb_change_outcome_screen_video_template9',function() {
		var data = jQuery(this);
	   	var sqb_mediauploader;
	   	window.sqb_img_class = jQuery(this).attr('data-class');	 
		if (sqb_mediauploader) {
			sqb_mediauploader.open();
			return;
		}
		sqb_mediauploader = wp.media.frames.file_frame = wp.media({
			title: 'Choose Video',
			button: {
				text: 'Choose Video'
			},
			library: {
		            type: [ 'video' ]
		    },
			multiple: false
		});
		
		sqb_mediauploader.on('select', function() {
			attachment = sqb_mediauploader.state().get('selection').first().toJSON();
			if(attachment.filesizeInBytes > 25000000){
				swal({
			      title: "Please note: File size has exceeded max limit of 25MB.",
			      html: "As it's a large video, you cannot upload it through SQB. We recommend using the \"link\" option instead of the \"upload\" option.<br><br>Upload it to Amazon S3 (make it a public link) or upload to your server directly via FTP/file manager and enter the link here. Don't use the video upload option. ",
			      customClass: "swal-750-width sqb-swal-left-alignment"
			   });
				return false;
			}
			jQuery('.sqb_delete_outcome_screen_video_template9').addClass('sqb-has-video');
			var number = Math.floor(1000 + Math.random() * 9000);
			var attachment_url = attachment.url;
			
			var splash_image = jQuery('.res_data_cont.active .outcome-section .outcome-Screen-Quiz-Template9-left-side').find('input[name="splash_image"]').val();
			var video_source = jQuery('.template9-outcome-screen-video-dropdown').val();
			if(splash_image){
				template9_video_option('.res_data_cont.active .outcome-section .outcome-Screen-Quiz-Template9-left-side', video_source, attachment_url, splash_image);
			}else{
				template9_video_option('.res_data_cont.active .outcome-section .outcome-Screen-Quiz-Template9-left-side', video_source, attachment_url);
			}
			jQuery('input[name="outcome_screen_video_hidden"]').val(attachment_url);
			jQuery('.outcome_screen_splash_image_option').show();
			jQuery('.outcome_screen_video_upload_url_outer').show();
			jQuery('.outcome_screen_video_upload_url').html(attachment_url);
		});
		sqb_mediauploader.open();
	});

	jQuery(document).on('click','.sqb_delete_outcome_screen_video_template9',function() {
		swal({
			title: "Are you sure you want to delete this video?",
			text: "It'll NOT be removed from WP media library but it'll be removed from SQB",
			showCancelButton: true,
			showCloseButton: true,
			confirmButtonColor: "#DD6B55",
			confirmButtonText: "Yes, Delete!",
			customClass: '',
		}).then((result) => {
			if (result.value) {
				jQuery('.sqb_delete_outcome_screen_video_template9').removeClass('sqb-has-video');
				jQuery('.res_data_cont.active .outcome-Screen-Quiz-Template9-left-side').html('');
				jQuery('.res_data_cont.active .outcome-section.Quiz-Template9-column-wrapper').addClass('sqb-no-video-found');
				jQuery('#template9_video_controls_outcome').prop('checked', false);
				jQuery('#template9_outcome_video_captions').prop('checked', false);
				jQuery('.template9_outcome_add_caption').hide();
				jQuery('.outcome_screen_video_upload_url_outer').hide();
				jQuery('.outcome_screen_video_upload_url').html('');
			}
		});	
	});

