jQuery(document).on("change", 'input[name="quiz_pagination"]', function(){
	var quiz_type = jQuery('input[name="quiz_type"]:checked').val();
	if(jQuery(this).val() == 'all'){
		jQuery('.show_next_button_outer').hide();
		var enable_branching = jQuery('input[name="enable_branching"]').prop('checked');
		if(enable_branching == true){
			swal("", "Sorry, can't enable pagination as  branching (quiz funnel) is enabled for this quiz.", "");
			 jQuery('input[name="quiz_pagination"][value="one_per_page"]').prop('checked', true);
			return false;
		}
		jQuery('.show_recomendation_ads_button').hide();
		if(jQuery('#ads_or_recommendation').prop('checked') == true){
			jQuery('#ads_or_recommendation').trigger('click');
		}
		jQuery('.question-pagination-option').hide('slow');
		jQuery('.category-options-for-question-pagination').hide('slow');
		if(jQuery('#show_back_button').prop('checked') == true){
			jQuery('#show_back_button').trigger('click');
		}
		jQuery('.all_question_same_page').show('slow');


		jQuery('.optin-before-questions-screen').hide();
		jQuery('input[name="optin-screen-position"][value="optin-after-questions-screen"]').trigger('click');

		jQuery(".display_correctans_options option[value=both]").hide();
		jQuery(".display_correctans_options option[value=each_page]").hide();
		jQuery(".display_correctans_options option").removeAttr('selected');
		jQuery(".display_correctans_options option[value=result_page]").attr('selected', 'selected');

		jQuery('.quiz_advanced_rule').hide();
		jQuery('.enable_branching_outer_wrapper').hide();
		jQuery('#show_next_button').prop('checked', false);
	}else if(jQuery(this).val() == 'fixed_number'){
		var enable_branching = jQuery('input[name="enable_branching"]').prop('checked');
		if(enable_branching == true){
			swal("", "Sorry, can't enable pagination as  branching (quiz funnel) is enabled for this quiz.", "");
			 jQuery('input[name="quiz_pagination"][value="one_per_page"]').prop('checked', true);
			return false;
		}
		jQuery('#show_next_button').prop('checked', true);
		jQuery('.question-pagination-option').show('slow');
		jQuery('.category-options-for-question-pagination').hide('slow');
		jQuery('.show_progress_bar_section').hide('slow');
		jQuery('#progress_bar').prop('checked', false);
		if(jQuery('#show_back_button').prop('checked') == true){
			jQuery('#show_back_button').trigger('click');
		}
		jQuery('.all_question_same_page').hide('slow');

		jQuery('.optin-before-questions-screen').show();


		jQuery('.quiz_advanced_rule').show();
		jQuery('.enable_branching_outer_wrapper').show();

		jQuery('.show_next_button_outer').hide();
		jQuery('#show_next_button').prop('checked', false);
		jQuery('.show_recomendation_ads_button').hide();

		jQuery(".display_correctans_options option[value=both]").hide();
		jQuery(".display_correctans_options option[value=each_page]").hide();

		jQuery(".display_correctans_options option").removeAttr('selected');
		jQuery(".display_correctans_options option[value=result_page]").attr('selected', 'selected');




	}else if(jQuery(this).val() == 'question_on_category'){
		var enable_branching = jQuery('input[name="enable_branching"]').prop('checked');
		if(enable_branching == true){
			swal("", "Sorry, can't enable pagination as  branching (quiz funnel) is enabled for this quiz.", "");
			 jQuery('input[name="quiz_pagination"][value="one_per_page"]').prop('checked', true);
			return false;
		}
		if(jQuery('#quiz_category_enable').prop('checked') == false){
			jQuery('#quiz_category_enable').trigger('click');
		}
		jQuery('#show_next_button').prop('checked', true);
		jQuery('.question-pagination-option').hide('slow');
		if(quiz_type == "scoring" || quiz_type == 'assessment'){
			jQuery('.category-options-for-question-pagination').show('slow');
		}else{
			jQuery('.category-options-for-question-pagination').hide('slow');
		}
		jQuery('.show_progress_bar_section').hide('slow');
		jQuery('#progress_bar').prop('checked', false);
		if(jQuery('#show_back_button').prop('checked') == true){
			jQuery('#show_back_button').trigger('click');
		}
		jQuery('.all_question_same_page').hide('slow');

		jQuery('.optin-before-questions-screen').show();

		jQuery('.quiz_advanced_rule').show();
		jQuery('.enable_branching_outer_wrapper').show();

		jQuery('.show_next_button_outer').show();
		jQuery('#show_next_button').prop('checked', false);
		jQuery('.show_recomendation_ads_button').hide();

		jQuery(".display_correctans_options option[value=both]").hide();
		jQuery(".display_correctans_options option[value=each_page]").hide();
		jQuery(".display_correctans_options option").removeAttr('selected');
		jQuery(".display_correctans_options option[value=result_page]").attr('selected', 'selected');
	}else{
		jQuery('.show_next_button_outer').show();
		jQuery('.question-pagination-option').hide('slow');
		jQuery('.show_recomendation_ads_button').show('slow');
		jQuery('.category-options-for-question-pagination').hide('slow');
		jQuery('.all_question_same_page').hide('slow');

		jQuery('.optin-before-questions-screen').show();

		jQuery(".display_correctans_options option[value=both]").show();
		jQuery(".display_correctans_options option[value=each_page]").show();

		jQuery('.quiz_advanced_rule').show();
		jQuery('.enable_branching_outer_wrapper').show();
	}
});

jQuery('.send_test_email').on('click', function(){
	jQuery('.mail-sent-name').text('');
	var quiz_name = jQuery('#quiz_name').val();
	var quiz_type = jQuery('input[name="quiz_type"]:checked').val();
	var admin_name = jQuery('#from_name').val();
	var admin_email = jQuery('#from_email').val();
	var subject = jQuery('#email_subject').val();
	var bodyText = tinymce.get('email_body').getContent();

	if(admin_name == ''){
		swal('Please enter the "From Name"');
		return false;
	}
	if(admin_email == ''){
		swal('Please enter the "From Email"');
		return false;
	}

	if(subject == ''){
		swal('Please enter "Subject"');
		return false;
	}

	if(bodyText == ''){
		swal('Please enter "Body"');
		return false;
	}  

	jQuery('.mail-sent-name').append(admin_email);
	var outcome_name = jQuery('.res_data_cont .outcome_name').val();
	var outcome_description = jQuery('.res_data_cont .result_temp_outer').find('#result_temp_contentid').html();

	var question_title = jQuery('.sqb_question_no.active').find('.question_details .question_title').html();
	var answer_title = jQuery('.sqb_question_no.active').find('.sql_ans_text').html();

	SQBShowLoader();
	jQuery.post(ajaxurl, {
		action: 'SQBSendTestEmail',
		quiz_name: quiz_name,
		quiz_type: quiz_type,
		admin_name: admin_name,
		admin_email: admin_email,
		subject: subject,
		bodyText: bodyText,
		outcome_name: outcome_name,
		outcome_description: outcome_description,
		question_title: question_title,
		answer_title: answer_title,
	}, function(response) {
		SQBHideLoader();
		response = JSON.parse(response);
		if(response == 'mailsent'){
			setTimeout(function(){
				jQuery('.send-test-email').show();
			},1000)
			jQuery('.send-test-email-error-msg').hide();
		}else{
			jQuery('.send-test-email').hide();
			setTimeout(function(){
				jQuery('.send-test-email-error-msg').show();
			},1000)
		}
	});
});

