jQuery('#opt_in_date_picker').on('click', function(){
	SQBShowLoader();
	jQuery('#myDatepickerOptinModal').modal('show');
	jQuery.post(ajaxurl, {
		action: 'sqbloaddatedata',
	}, function(response) {
		SQBHideLoader();
		response = JSON.parse(response);
		if(response){
			var date_data = response['date_data'].split('|');

			var array_month = date_data[0].split(",");
			jQuery.each(array_month, function(i, keyword){
				jQuery( "input[name='optin_month_names']" ).each(function( index ) {
					if(index == i){
						jQuery(this).val(keyword);
					}
				});
			});

			var array_day = date_data[1].split(",");
			jQuery.each(array_day, function(i, keyword){
				jQuery( "input[name='optin_day_names']" ).each(function( index ) {
					if(index == i){
						jQuery(this).val(keyword);
					}
				});
			});
		}
	});


	
});

