		var table_data = '<td>first_name</td> <td>email</td> <td>quiz_name</td> <td>quiz_type</td> <td>quiz_desc</td> <td>outcome_name</td> <td>all_tags_name</td>';
		var quiz_type = jQuery('#quiz_type_switch').val();
