jQuery(document).on('click','.sqb-delete-outcome-rank', function(){
	swal({
		title: "Are you sure you want to delete ?",
		text: "",
		showCancelButton: true,
		showCloseButton: true,
		confirmButtonColor: "#DD6B55",
		confirmButtonText: "Yes, Delete!",
		customClass: '',
	}).then((result) => {
		if (result.value) {
			var id = jQuery(this).attr('data-id');
			jQuery('.category_ad_tbody .tr'+id).remove();
			var quiz_id = jQuery('#edit_id').val();
			jQuery.post(ajaxurl, {
				action: 'sqbSaveOutcomeRank',
				action_val: 'delete', 
				id: id, 
				quiz_id: quiz_id, 
				}, function(response) {
					response = JSON.parse(response);
					jQuery('input[name="outcome_rank_edit_id"]').val('');
					outcome_rank_data_html = response.outcome_rank_data_html;	
					jQuery('<span class="deleted_data_msg">Deleted Successfully</span>').insertAfter(".outcome-rank-btn");
					setTimeout(function(){
						jQuery('#quiz_outcome_rank .deleted_data_msg').remove();
					}, 2000);

					jQuery('.outcome_rank_main_ad_table tbody').html(outcome_rank_data_html);
			});		
		}
	});	
});
