jQuery('.save_outcome_rank_rule').on('click', function(){
	var quiz_id = jQuery('#edit_id').val();
	var outcome_id = jQuery('.all_outcome_rank_div option:selected').val();
	var outcome_rank_edit_id = jQuery('input[name="outcome_rank_edit_id"]').val();

	if(outcome_id == 0 ){
		jQuery('.outcome-rank-select-error-msg').show();
		jQuery('.all_outcome_rank_div').focus();
		return false;
	}else{
		jQuery('.outcome-rank-select-error-msg').hide();
	}

	var outcome_description = tinymce.get('outcome_rank_description').getContent();
	if(outcome_description == ''){
		jQuery('.outcome-rank-description-error-msg').show();
		return false;
	}else{
		jQuery('.outcome-rank-description-error-msg').hide();
	}

	jQuery('.save_outcome_rank_rule').text('Saving...');

	jQuery.post(ajaxurl, {
		action: 'sqbSaveOutcomeRank',
		action_val: 'save',
		outcome_id: outcome_id,
		quiz_id: quiz_id,
		outcome_description: outcome_description,
		outcome_rank_edit_id: outcome_rank_edit_id,
		}, function(response) {
			response = JSON.parse(response);

			if(response.msg == 'Already'){
				jQuery('<span class="already_data_msg">Already Added</span>').insertAfter(".outcome-rank-btn");
				setTimeout(function(){
					jQuery('#quiz_outcome_rank .already_data_msg').remove();
				}, 2000);
				jQuery('.save_outcome_rank_rule').text('Save');
				return false;
			}

			jQuery('.save_outcome_rank_rule').text('Save');
			jQuery('input[name="outcome_rank_edit_id"]').val('');
			outcome_rank_data_html = response.outcome_rank_data_html;	
			jQuery('<span class="saved_data_msg">Saved Successfully</span>').insertAfter(".outcome-rank-btn");
			setTimeout(function(){
				jQuery('#quiz_outcome_rank .saved_data_msg').remove();
			}, 2000);

			jQuery('.outcome_rank_main_ad_table tbody').html(outcome_rank_data_html);
			
			jQuery('.all_outcome_rank_div').val('0');
			tinymce.get("outcome_rank_description").setContent('');
			jQuery('input[name="outcome_rank_edit_id"]').val('');

		});

});

