jQuery(document).on('click', '.cat_add_merge_tag_el', function () {
    var el = jQuery(this).attr('data-copyel');
    var content = jQuery('#' + el).html();

    // Create a temporary textarea to copy the content
    var tempTextArea = jQuery('<textarea>');
    jQuery('body').append(tempTextArea); // Append to body
    tempTextArea.val(content).select(); // Set the content and select it

    try {
        // Execute the copy command
        document.execCommand('copy');
        console.log('Content copied to clipboard');

        // Change button text to "Copied"
        var button = jQuery(this);
        var originalText = button.text();
        button.text('Copied!');

        // Revert text back to "Copy" after 2 seconds
        setTimeout(function () {
            button.text(originalText);
        }, 2000);
    } catch (err) {
        console.error('Unable to copy to clipboard', err);
    }

    // Remove the temporary textarea
    tempTextArea.remove();
});


jQuery('#enabled_advanced').change(function(){ 		 
	if(jQuery(this).prop('checked')){
		jQuery('.quiz_advanced_options').show();
		var enabled_advanced = 	"Y";
		var advanced_rules_option = 1;	
		var select_temp = jQuery('input[name="select_temp"]:checked').val();

		if(jQuery('.ques_ans_contain .sqb_questions_wrapper .sqb_question_no').length > 0){
			jQuery('.ques_ans_contain .sqb_questions_wrapper .sqb_question_no').each(function(index_question){
				if(select_temp == 'template7'){
					if(jQuery(this).find('.question_div_outer .template7-skip-question-button').find('input[name="skipquestion"]').prop('checked') == true){
						advanced_rules_option = 0;
					}
				}else if(select_temp == 'template8'){
					var allow_skip_ques_status = jQuery(this).find('.question_div_outer').find('.skip-question-action').css('display');
					if(allow_skip_ques_status != 'none'){
						advanced_rules_option = 0;
					}
				}else if(select_temp == 'template6'){
					if(jQuery(this).find('.question_div_outer .template8_question_screen_setting_right-side').find('.skip-btn-temp-8 input[name="allow_skip_ques"]').prop('checked') == true){
						advanced_rules_option = 0;
					}
				}else{
					if(jQuery(this).find('input[name="allow_skip_ques"]').prop('checked') == true){
						advanced_rules_option = 0;
					}
				}
			});
		}

		if(advanced_rules_option == 0){
			swal('','Sorry, can\'t enable advanced outcome rules as skip question is enabled for this quiz.','');
			jQuery('.quiz_advanced_options').hide();
			jQuery('#enabled_advanced').prop('checked', false);
			return false;
		}
	}else{
		jQuery('.quiz_advanced_options').hide();
		var enabled_advanced = 	"N";	
	}
	var quiz_id = jQuery('#edit_id').val();	
	
	jQuery.post(ajaxurl, {
		action: 'sqbSaveAdvanced',
		security: SQBVar.sqbSaveAdvanced,
		action_val: 'enabled_advanced_sett',
		enabled_advanced: enabled_advanced,
		ques_id: 0,
		answers_id: '',
		outcome_id: 0,
		skip_optin: '',
		quiz_id: quiz_id,
	}, function(response) {
		
	});	
});


