	jQuery('.all_categ_div').val(category_id);
	jQuery('.category_all_outcome_div').val(outcome_id);
	jQuery('input[name="start_range_cat"]').val(start_range);
	jQuery('input[name="end_range_cat"]').val(end_range);
	
