	jQuery(document).on('click', '.save_advanced_rule', function(){		 		
	var enabled_advanced = "N";	
	if(jQuery('#enabled_advanced').prop('checked') == true){	
		var enabled_advanced = 	"Y";			
	}		
	var answers_id = '';			
	var quiz_id = jQuery('#edit_id').val();	
	var adv_rule_id = jQuery('#adv_rule_id').val();	
	var skip_optin = jQuery('.ar_skip_optin  option:selected').val();	
	var skip_quiz = jQuery('.sqb_skip_quiz  option:selected').val();	
	var ques_id = jQuery('.all_ques_div option:selected').val();	
	var outcome_id = jQuery('.quiz_advanced_options .all_outcome_div option:selected').val();	
	var answers_id =  jQuery('.selected_answers_cls').map(function(i,n) {	
		return jQuery(n).attr('data-answer-id');	
	}).get().join(',');	
	if(enabled_advanced =="Y"){	
		if(ques_id == 0 ){	
			jQuery('.advrule-question-error').show();
			jQuery('.all_ques_div').focus();	
			return false;	
		}	
	
		if(outcome_id ==0 ){	
			swal("Please select an outcome");	
			jQuery('.all_outcome_div').focus();	
			return false;	
		}	
	}	
	var complex_advance_rules = [];	
	var validate_rep = true;	
	jQuery('.condition-rules-outer').find('.advrule-question-error').hide();	
	jQuery('.condition-rules-outer').find('.advrule-error').hide();	
	jQuery('.condition-rules-outer').each(function(i, obj) {	
		var q = jQuery(this).find('.all_ques_div').val();	
    var a = jQuery(this).find('.all_resources_data').val();	
    if(q == '' || q == 0){
    	jQuery(this).find('.advrule-question-error').show();	
			jQuery(this).find('.all_ques_div').focus();	
			validate_rep = false;	
			return false;	
    }else if(a == ''){
			jQuery(this).find('.advrule-error').show();	
			jQuery(this).find('.all_ques_div').focus();	
			validate_rep = false;	
			return false;	
		}else{	
			validate_rep = true;	
		}	
	});	

	if(!validate_rep){	
		return false;	
	}	
	jQuery('.condition-rules-outer').each(function(i, obj) {	
	   var q = jQuery(this).find('.all_ques_div').val();	
	   var a = jQuery(this).find('.all_resources_data').val();	
	   var e = jQuery(this).find('.adv_exp').val();	
	   var valueToPush = { }; // or "var valueToPush = new Object();" which is the same	
		valueToPush["question"] = q;	
		valueToPush["answer"] = a;	
		valueToPush["expression"] = e;	
		complex_advance_rules.push(valueToPush);	
	});	
	jQuery('.save_advanced_rule').text("Saving...");	
	jQuery.post(ajaxurl, {	
		action: 'sqbSaveAdvanced', 	
		security: SQBVar.sqbSaveAdvanced,	
		action_val: 'save',	
		adv_rule_id : adv_rule_id,	
		enabled_advanced: enabled_advanced,	
		ques_id: ques_id,	
		complex_advance_rules : complex_advance_rules,	
		answers_id: answers_id,	
		outcome_id: outcome_id,	
		skip_optin: skip_optin,	
		skip_quiz: skip_quiz,	
		quiz_id: quiz_id,	
		}, function(response) {	
			if(enabled_advanced =="Y"){	
				response = JSON.parse(response);								
				if(response.msg =='err'){	
					if(response.ansid > 0){	
						var anstext = jQuery('.optionans'+response.ansid).text(); 	
						//var textdata =  "Sorry, can't create multiple rules for the same answer. These answers are already part of a rule.<br/> <strong>"+anstext+"</strong>";	
						var textdata =  "Sorry, can't create multiple rules for the same answer. This answer is already part of a rule.<br/> <strong>"+anstext+"</strong>";	
						swal({ 	
							html:textdata,	
							 title:'', 	
						});	
					}		
				}else if(response.msg =='Exists'){	
					var textdata =  "Sorry, can't create multiple rules for the same question/answer.";	
					swal({ 	
						html:textdata,	
							title:'', 	
					});	
				}else{	
					jQuery('.adrule_add_new_rule').trigger('click');								
					rule_data_html = response.rule_data_html;								
					jQuery('.advanced-rules-inner-data').html(rule_data_html); 						
				}	
			}	
			jQuery('.save_advanced_rule').text("Save");	
	});	
});

