jQuery(document).on('click', '.save_advanced_category_rule', function(){		 	

	var enabled_advanced_category = "N";

	if(jQuery('input[name="outcome_based"]:checked').val() == 'category'){
		var enabled_advanced_category = "Y";		
	}	
			
	var quiz_id = jQuery('#edit_id').val();
	var category_id = jQuery('.all_categ_div option:selected').val();
	var outcome_id = jQuery('.category_all_outcome_div option:selected').val();
	var start_range = '';
	var end_range = '';
	
		if(category_id == 0 ){
			swal("Please select a Category");
			jQuery('.all_categ_div').focus();
			return false;
		}

		var category_type = jQuery('input[name="category_type"]:checked').val();

		if(category_type == 'category_total'){

			var start_range = jQuery('input[name="start_range_cat"]').val();
			var end_range = jQuery('input[name="end_range_cat"]').val();
			if(start_range == ''){
				swal("Please Enter Start Range");
				jQuery('input[name="start_range_cat"]').focus();
				return false;
			}

			if(end_range == ''){
				swal("Please Enter End Range");
				jQuery('input[name="end_range_cat"]').focus();
				return false;
			}			
		}

		if(outcome_id ==0 ){
			swal("Please select an outcome");
			jQuery('.category_all_outcome_div').focus();
			return false;
		}

	var advance_edit_id = jQuery('input[name="category_edit_id"]').val();
	jQuery('.save_category_advanced_rule').text("Saving...");

	jQuery.post(ajaxurl, {
		action: 'sqbSaveCategoryAdvanced',
		security: SQBVar.sqbSaveCategoryAdvanced,
		action_val: 'save',
		enabled_advanced_category: enabled_advanced_category,
		category_id: category_id,
		start_range : start_range,
		end_range : end_range,
		outcome_id: outcome_id,
		quiz_id: quiz_id,
		advance_edit_id: advance_edit_id,
		}, function(response) {
				jQuery('.custom_fields_table_outer').show();
				jQuery('input[name="category_edit_id"]').val('');
				jQuery('input[name="start_range_cat"]').val('');
				jQuery('input[name="end_range_cat"]').val('');
				jQuery('.category_adrule_add_new_rule').trigger('click');

				response = JSON.parse(response);		
				if(response.error =='Already Exist'){
					var textdata =  "This rule already exists.";
					swal({ 
						html:textdata,
						 title:'', 
						   
					});
				}else if(response.error =='Range already exists'){
					var textdata =  "The range is already defined for this category.";
					swal({ 
						html:textdata,
						 title:'', 
						   
					});
				}else{							
					rule_data_html = response.rule_data_html;							
					remaining_category = response.remaining_category;	
					jQuery('.category_ad_table tbody').html(rule_data_html);
					if(remaining_category != ''){
						jQuery('.custom_fields_table ul').html(remaining_category); 					
					}else{
						jQuery('.category-mapped .title-label').hide();
						jQuery('.custom_fields_table ul').html('');
					}
				}
			jQuery('.save_category_advanced_rule').text("Save");

			var category_type = jQuery('input[name="category_type"]:checked').val();
			var outcome_based = jQuery('input[name="outcome_based"]:checked').val();
			if(category_type == 'category_total' && outcome_based == 'category'){
				jQuery('.cat-range-cell').show();
			}else{
				jQuery('.cat-range-cell').hide();
			}
	});

});

