/*Hide Show start Screen For popup*/
var quiz_page_option = jQuery('input[name="quiz_display"]:checked').val();
var defaultpopup_type1 = jQuery('input[name="defaultpopup_type"]:checked').val();
if(quiz_page_option == 'popup' && defaultpopup_type1 == 'popup'){
	jQuery('.show_start_screen').hide();	
}

/* show/hide start screen for option inpage and Bottom Popup*/
var show_start_screen = jQuery('input[name="show_start_screen"]:checked').val();
if(show_start_screen == 'Y'){
	jQuery('.show-start-screen-settings').show();		
	jQuery('.show-quiz-screen-setting').hide()
	jQuery('.show-lead-page-for-form-quiz-type').hide();
	jQuery('.tab-show-start-screen-settings').show();
	
	jQuery('.back-start-screen-setting').show();
	jQuery('.back-basic-screen-setting').hide();
	
	jQuery('.ass-prev-start-setting').show();
	jQuery('.asses-quiz-screen-setting').hide();

}else{
	var quiz_type = jQuery('input[name="quiz_type"]:checked').val();
	if(quiz_type == 'form'){
		setTimeout(function(){
			jQuery('.show-quiz-screen-setting').hide();
			jQuery('.template-ecommerce').hide();
			var popup_val = jQuery('input[name="popup_type"]:checked').val();
			if(popup_val == 'default'){
				jQuery('.tab-show-start-screen-settings').show();
			}else{
				jQuery('.tab-show-start-screen-settings').hide();
			}
			jQuery('.allow_retake_quiz_outer').hide();
		},1000);
		jQuery('.show-lead-page-for-form-quiz-type').show();

	}else{
		if(quiz_type == 'poll'){
			jQuery('.show-lead-page-for-form-quiz-type').hide();
		}
		jQuery('.show-quiz-screen-setting').show();
		jQuery('.tab-show-start-screen-settings').hide();
	}

	jQuery('.show-start-screen-settings').hide();		
	jQuery('.tab-show-start-screen-settings').hide();
	
	jQuery('.back-start-screen-setting').hide();
	jQuery('.back-basic-screen-setting').show();

	jQuery('.ass-prev-start-setting').hide();
	jQuery('.asses-quiz-screen-setting').show();
}

