jQuery("body").on('click','.clone-qa-btn', function(){
	var clone_question_id = jQuery(this).closest('.sqb_question_no').find('.sqb_question_enable_drag_drop').attr('data-id');
	
	if(jQuery('.left_side_question_list ul li').length >= (sqb_add_question_pagination_limit)){
	var check_question = jQuery('.sqb_question_no .question-screen .quiz_comon_template[data-id="%%SQBQUESTIONID%%"]').length;
	if(check_question != 0){
			swal("","Please save the question first.","");
			return false;
	}
	var page = jQuery('select.selected-question').val();
	 if(typeof page == undefined || typeof page == "undefined"){
		 page = 1;
	 }
	 if(jQuery('.left_side_question_list ul li').length == (sqb_add_question_pagination_limit)){
		 page = parseInt(page)+1;
	 }
		var clone_existing_question_call_var = 'Y';
		//sqb_showPage(page, sqb_add_question_pagination_limit, 'N',clone_existing_question_call_var, clone_question_id );
		
		window.location.href = sqb_get_url_without_edit_quiz_query_string()+"&sqb_clone=Y&clone_question_id="+clone_question_id;
	
	}else{
		clone_existing_question(clone_question_id);
	} 
	
});




