jQuery(document).on('click' , '.saveTempVideo' , function(){
	var dataType = jQuery(this).attr('data-type');
	var type = jQuery('.'+dataType+'TemplateVideoTypeDrop').attr('data-value');
	var typeText = jQuery('.'+dataType+'TemplateVideoTypeDrop').text();
	var url = jQuery('#'+dataType+'TemplateVideoUrl').val();
		
	url  = jQuery.trim( url );
	if(type == '0'){
		swal("", "Please select the source", "");
		return false;
	}

	var width = jQuery('#start_temp_width').val();
	var aspectRatio = '1';
	var values = parseFloat(9) / parseFloat(16);
	var height = parseFloat(width) * parseFloat(values);
	if(jQuery('input[name=aspect_ratio_rd]:checked').val() == 2){
		var values = parseFloat(3) / parseFloat(4);
		height = parseFloat(width) * parseFloat(values);
		aspectRatio = '2';
	}else if(jQuery('input[name=aspect_ratio_rd]:checked').val() == 3){
		var values = parseFloat(1) / parseFloat(1);
		height = parseFloat(width) * parseFloat(values);
		aspectRatio = '3';
	}else if(jQuery('input[name=aspect_ratio_rd]:checked').val() == 4){
		var values = parseFloat(9) / parseFloat(16);
		height = parseFloat(width) * parseFloat(values);
		aspectRatio = '4';
	}

	if(type == 'youtube'){
		var videoId = sqb_get_youtube_iframe(url);
		var html = '<iframe width="560" height="315" src="//www.youtube.com/embed/' 
		+ videoId + '" frameborder="0" allowfullscreen></iframe>';

		

	}else if(type == 'link'){
		var html = '<video controls><source src="'+url+'" type="video/mp4"></video>';
	}else{
		var html = url;
	}
	

	

	if(dataType == 'outcome'){

		

		jQuery('.res_data_cont.active').find('.'+dataType+'TemplateYoutubeVideoOuter').html(html);
				
		if(type != 'shortcode'){		
			jQuery('.res_data_cont.active').find('.'+dataType+'TemplateYoutubeVideoOuter').css('height', height);
			jQuery('.res_data_cont.active').find('.'+dataType+'TemplateYoutubeVideoOuter').css('min-height', height);
			jQuery('.res_data_cont.active').find('.video-element-outer').css('min-height' , '200px');
			jQuery('.res_data_cont.active').find('.video-element-outer').css('height' , '400px');
		}

		jQuery('.res_data_cont.active').find('.'+dataType+'TemplateYoutubeVideoOuter').show();
		jQuery('.res_data_cont.active').find('.'+dataType+'TemplateInsertVideoOuter').hide();	

		jQuery('.res_data_cont.active').find('.outcome_video_url').val(url);
		jQuery('.res_data_cont.active').find('.outcome_show_video').val('Y');
		jQuery('.res_data_cont.active').find('.outcome_video_link_type').val(type);
		jQuery('.res_data_cont.active').find('.outcome_video_link_type_text').val(typeText);
		jQuery('.res_data_cont.active').find('.outcome_video_aspect').val(aspectRatio);
		jQuery('#outcome-video-insert').modal('hide');
	}else if(dataType == 'question'){

		

		jQuery('.sqb_question_no.active').find('.'+dataType+'TemplateYoutubeVideoOuter').html(html);
				
		if(type != 'shortcode'){		
			jQuery('.sqb_question_no.active').find('.'+dataType+'TemplateYoutubeVideoOuter').css('height', height);
			jQuery('.sqb_question_no.active').find('.'+dataType+'TemplateYoutubeVideoOuter').css('min-height', height);
			jQuery('.sqb_question_no.active').find('.video-element-outer').css('min-height' , '200px');
			jQuery('.sqb_question_no.active').find('.video-element-outer').css('height' , '400px');
		}

		jQuery('.sqb_question_no.active').find('.'+dataType+'TemplateYoutubeVideoOuter').show();
		jQuery('.sqb_question_no.active').find('.'+dataType+'TemplateInsertVideoOuter').hide();	

		jQuery('.sqb_question_no.active').find('.question_video_url').val(url);
		jQuery('.sqb_question_no.active').find('.question_show_video').val('Y');
		jQuery('.sqb_question_no.active').find('.question_video_link_type').val(type);
		jQuery('.sqb_question_no.active').find('.question_video_link_type_text').val(typeText);
		jQuery('.sqb_question_no.active').find('.question_video_aspect').val(aspectRatio);
		jQuery('#question-video-insert').modal('hide');
	}else if(dataType == 'leadScreen'){
		jQuery('#video-insert').modal('hide');
		jQuery('.'+dataType+'TemplateYoutubeVideoOuter').html(html);
			
		if(type != 'shortcode'){				
			jQuery('.'+dataType+'TemplateYoutubeVideoOuter').css('height', height);
			jQuery('.'+dataType+'TemplateYoutubeVideoOuter').css('min-height', height);
			jQuery('.optin_template_html_preview_outer').find('.video-element-outer').css('min-height' , '200px');
			jQuery('.optin_template_html_preview_outer').find('.video-element-outer').css('height' , '400px');
		}

		jQuery('.'+dataType+'TemplateYoutubeVideoOuter').show();
		jQuery('.'+dataType+'TemplateInsertVideoOuter').hide();
		jQuery('#leadScreen-video-insert').modal('hide');
	}else{
		jQuery('#video-insert').modal('hide');
		jQuery('.'+dataType+'TemplateYoutubeVideoOuter').html(html);
			
		if(type != 'shortcode'){				
			jQuery('.'+dataType+'TemplateYoutubeVideoOuter').css('height', height);
			jQuery('.'+dataType+'TemplateYoutubeVideoOuter').css('min-height', height);
			jQuery('.start_temp_container').find('.video-element-outer').css('min-height' , '200px');
			jQuery('.start_temp_container').find('.video-element-outer').css('height' , '400px');
		}

		jQuery('.'+dataType+'TemplateYoutubeVideoOuter').show();
		jQuery('.'+dataType+'TemplateInsertVideoOuter').hide();	
	}
	sqb_resizeable_video(dataType);

	
});

