jQuery('#sqbverifyemail').change(function(){
	var sqbverifyemail = jQuery(this).prop('checked');
	if(sqbverifyemail){
		SQBShowLoader();

		jQuery.post(ajaxurl, {
			action: 'sqbverifyemailvalidation',
		},function(response) {
			SQBHideLoader();
			response = JSON.parse(response);

			var evmm = jQuery('#sqbverifyemail').attr('data-evm');

			if(evmm == 'reoon'){
				if(response == 'notset'){
					swal("","To use this feature, you need to integrate with Reoon service and enter key <a href='../wp-admin/admin.php?page=sqb_settings&tab=email_verification' target='_blank'>here</a>.","");
					jQuery('#sqbverifyemail').prop('checked',false);
				}else{
					jQuery('#sqb_verify_email').val('Y');
				}
			}else{
				if(response == 'notset'){
					swal("","To use this feature, you need to integrate with Quick Email Verification service and enter key <a href='../wp-admin/admin.php?page=sqb_settings&tab=email_verification' target='_blank'>here</a>.","");
					jQuery('#sqbverifyemail').prop('checked',false);
				}else{
					jQuery('#sqb_verify_email').val('Y');
				}
			}
		});



	}else{
		jQuery('#sqb_verify_email').val('N');
	}
});

