//outcome top buttons click
jQuery(document).on("click", '.left_side_outcome_list li a', function(e){ 
	e.preventDefault();
	var href_val = jQuery(this).attr("href");	
	jQuery('.left_side_outcome_list li a').removeClass("active show");	
	jQuery(this).addClass("active show");	
	jQuery('.res_data_cont').removeClass("active show");	
	jQuery('.res_data_cont').hide();		  
	jQuery(href_val).addClass("active show");	
	jQuery(href_val).show();
	var outcome_show_video = jQuery(href_val+'.res_data_cont.active').find('.outcome_show_video').val();
	if(outcome_show_video == 'Y'){
		jQuery('#outcomeshowHide_video').prop('checked' , true);
	}else{
		jQuery('#outcomeshowHide_video').prop('checked' , false);		
	}


	/*--------*/
	var selected_template = jQuery('input[name="select_temp"]:checked').val();
	if(selected_template == 'template9'){
		setTimeout(function(){
			outcome_video_delete_action();
			template9_outcome_screen_data();

			if(jQuery('.res_data_cont.active .outcome-section').hasClass('sqb-template-bg-video-left') || jQuery('.res_data_cont.active .outcome-section').hasClass('sqb-template-bg-video-right')){
					playSilentVideo(jQuery('.res_data_cont.active').find('.outcome-Screen-Quiz-Template9-left-side'));
				}

		},500);
	}



	jQuery('.continue-url').val('');
	if (jQuery(".res_data_cont.active .outcome-section .take-quiz-btn").attr('data-continueurl')) {
		var continue_url = jQuery(".res_data_cont.active .outcome-section .take-quiz-btn").attr('data-continueurl');
		jQuery('.continue-url').val(continue_url);
	}

	if (jQuery('.res_data_cont.active .outcome-section #result_temp_btnid').css('display') == 'none'){
		jQuery('#show_hide_continue').prop('checked', false);
		jQuery('.continue-url-main-div').hide();
	}else if(jQuery('.res_data_cont.active #result_temp_btnid.pos_relative .d-inline-block').length == 0){
		jQuery('#show_hide_continue').prop('checked', false);
		jQuery('.continue-url-main-div').hide();
	}else{
		jQuery('#show_hide_continue').prop('checked', true);
		jQuery('.continue-url-main-div').show();
	}

	/*-------*/
	jQuery('.res_data_cont.active .sqb_res_collapse, .res_data_cont.active ').show();	
	var template_no = jQuery('input[name="select_temp"]:checked').val();
	if( template_no == 'template5'){
		setTimeout(function(){
			
			var result_temp_left_sction_clr = jQuery('.result_template_html_preview_outer').find(href_val).find('.Quiz-result-Template5-left').css('background-color');
			if(typeof result_temp_left_sction_clr != 'undefined'){
				jQuery('#result_temp_left_sction_clr,#result_temp_left_sction_clr_div').colorpicker('setValue', result_temp_left_sction_clr);
			}
			var result_temp_right_sction_clr = jQuery('.result_template_html_preview_outer').find(href_val).find('.Quiz-result-Template5-right').css('background-color');
			if(typeof result_temp_right_sction_clr != 'undefined'){
				jQuery('#result_temp_right_sction_clr,#result_temp_right_sction_clr_div').colorpicker('setValue', result_temp_right_sction_clr);
			}
			
			sqb_load_outcomes_background_image_customizer_values();
			
		}, 100);
	}
		
});		

