// result screen
jQuery(document).on("click", '.add_new_result', function(e){
	e.preventDefault();
	var quiz_id = jQuery('input[name="edit_id"]').val();
	var quiz_type = jQuery('input[name="quiz_type"]:checked').val();
	var res_data_cont = jQuery('.res_data_cont').length;
	if(jQuery('.res_data_cont').length >= (sqb_add_outcome_pagination_limit)){
		jQuery('.result_template_html_preview_outer .res_data_cont').each(function(){
			var outcome_id = jQuery(this).find('.sqb_remove_section').data('key');
			if(outcome_id == undefined || outcome_id == null || outcome_id == ''){
				swal("","Please save Outcome","");
				return false;
			}
		});
		
		window.location.href = sqb_get_url_without_edit_quiz_query_string()+"&oc_action=add";
	}else{
		jQuery('.no_result').hide(); 
		jQuery('.sqb_res_collapse').removeClass('show');
		var selected_template = jQuery('input[name="select_temp"]:checked').val();
		if(selected_template == 'template8'){
			selected_template = 'template8'
		} else if(selected_template == 'template9'){
			selected_template = 'template9';
		} else if(selected_template != 'template5'){
			selected_template = 'template2';
		}
	if(selected_template == 'template9'){
		setTimeout(function(){
			jQuery('input[name="template9_outcome_screen_layout_option"][value="split_screen"]').prop('checked', true);
			jQuery('input[name="template9_outcome_screen_split_option"][value="video_left"]').prop('checked', true);
			jQuery('.outcome-screen-video-settings-show-hide').show();
			jQuery('.template9_outcome_split_screen_options').show();
			if(jQuery('.res_data_cont.active .outcome-Screen-Quiz-Template9-left-side').find('.video_controls').val() == 'Y'){
				jQuery('#template9_video_controls_outcome').prop('checked', true);
			}else{
				jQuery('#template9_video_controls_outcome').prop('checked', false);
			}

			if(jQuery('.res_data_cont.active .outcome-Screen-Quiz-Template9-left-side').find('.video_source').val() == 'upload'){
				var video_url = jQuery('.lead-Screen-Quiz-Template9-left-side').find('input[name="video_id"]').val();
				jQuery('input[name="outcome-screen-video-upload-url"]').val(video_url);
				jQuery(".template9-outcome-screen-video-dropdown").val("link").change();
				jQuery('.template9-outcome-screen-upload-option').hide();
				jQuery('.template9-outcome-screen-link-option').show();
			}else {
				jQuery(".template9-outcome-screen-video-dropdown").val("upload").change();
				jQuery('.template9-outcome-screen-upload-option').show();
				jQuery('.template9-outcome-screen-link-option').hide();	
			}


			var outcome_screen_play_btn_clr = jQuery('.res_data_cont.active .outcome-Screen-Quiz-Template9-left-side').find('.video_play_btn_color').val()

			if(outcome_screen_play_btn_clr){
				jQuery('#outcome-screen-template9-play-button-background-color').colorpicker('setValue', outcome_screen_play_btn_clr);
			}else{
				jQuery('#outcome-screen-template9-play-button-background-color').colorpicker('setValue', '#ffffff');
			}
			var outcome_background_color = jQuery('.res_data_cont.active').find('.outcome-section').css('background-color');
			jQuery('.temp9_outcome_screen_backgroud_color').colorpicker('setValue',outcome_background_color);
			jQuery('.outcome_screen_splash_image_option').hide();
			jQuery('.outcome_screen_video_upload_url_outer').hide();
			jQuery('.outcome_screen_video_upload_url').html('');
		},2000);
	}

		jQuery('input[name="template9_outcome_screen_layout_option"][value="split_screen"]').trigger('click');

		sqb_get_result_temp(selected_template, "result","");	
				
		jQuery('html, body').animate({
			scrollTop: jQuery(".create_quiz_top_tabs_div").offset().top
		}, 2000);

		
		var template_no = jQuery('input[name="select_temp"]:checked').val();
		var outcome_based = jQuery('input[name="outcome_based"]:checked').val();
	}
	jQuery('.result_temp_static_div .Quiz-Outcome-Answer-outer .Template-Customize-setting-outer').show();
	jQuery('.outocome_right_side_customizer').show();
});

