function load_pdf_content(){
	SQBShowLoader();
	jQuery.post(ajaxurl, {
			action: 'sqb_load_pdf_content',
	}, function(response) {		 
		SQBHideLoader();
		response = JSON.parse(response);	
		if(response.pdf_name){
			jQuery('.pdf-content-data select').html(response.pdf_name);		  
		}

		if(response.noContent == 'noContent'){
			jQuery('.no-pdf-created').show();
			jQuery('.hide_for_no_content').hide();
			jQuery('.pdf-how-it-work').show();
			jQuery('.outcome-save-pdf-html').hide();
		}else{
			jQuery('.pdf-how-it-work').hide();
			jQuery('.hide_for_no_content').show();
			jQuery('.no-pdf-created').hide();
			jQuery('.outcome-save-pdf-html').show();
		}
	});
}

