function sqb_outcome_side_popup(quiz_id){
SQBShowLoader();
jQuery.post(ajaxurl, {
		action: 'sqb_get_formula_sidepopup',
		quiz_id:quiz_id,
		
	}, function(response) {
		SQBHideLoader();
		jQuery('.sqb_loading_wrapper').hide();
		jQuery('.formula-outcome-mapping-side-popup').show();
		jQuery('.formula-outcome-mapping-side-popup').addClass('active_Side_Popup');
		jQuery('body').addClass('sidepopup-active');

		jQuery('.formula-outcome-mapping-side-popup').show('slow');
		response = JSON.parse(response);	
		jQuery('.get-formulas').empty();
		jQuery('.outcome-list').empty();
		jQuery('.get-formulas').append(response.formula_list);
		jQuery('.outcome-list').append(response.outcome_list);		
	});
}

function sqb_load_formula_data(formula_id){
var quiz_id = jQuery('#edit_id').val();
jQuery.post(ajaxurl, {
		action: 'sqb_get_formula_data',
		formula_id:formula_id,
		quiz_id:quiz_id,
	}, function(response) {
		jQuery('.select-formula').val(formula_id);
		response = JSON.parse(response);
		if(response.html){
			jQuery('.formula-outcome-map .formula_tbody').empty();
			jQuery('.formula-outcome-map .formula_tbody').append(response.html);
		}else{
			jQuery('.formula-outcome-map .formula_tbody').empty();
			jQuery('.formula-outcome-map .formula_tbody').append('<tr><td colspan="5">No data Found</td></tr>');
		}

		if(response.number_range == 'number'){
			jQuery('.formula-number-range').val(response.number_range);
			jQuery('input[name="outcome-mapping-number"]').val(response.formula_values);
			jQuery('.select-formula-outcome').val(response.outcome_id);
			jQuery('.number-range').show();
			jQuery('.select-outcome').show();
			jQuery('.formula-number').show();
			jQuery('.formula-range').hide();
			jQuery('.outcome-mapping-save').show();				
		}else if(response.number_range == 'range'){
			jQuery('.formula-number-range').val(response.number_range);
			jQuery('.select-formula-outcome').val(response.outcome_id);
			var result = response.formula_values.split('-');
			jQuery('input[name="outcome-mapping-start"]').val(result[0]);
			jQuery('input[name="outcome-mapping-end"]').val(result[1]);
			jQuery('.number-range').show();
			jQuery('.select-outcome').show();
			jQuery('.formula-range').show();
			jQuery('.formula-number').hide();
			jQuery('.outcome-mapping-save').show();				
		}else{
			jQuery(".formula-number-range").val(jQuery(".formula-number-range option:first").val());
			jQuery('.number-range').show();
			jQuery('.select-outcome').show();
			jQuery('.formula-number').hide();
			jQuery('.formula-range').hide();
			jQuery('.outcome-mapping-save').show();
		}
				
	});
}

function save_outcome_mapping(){
var quiz_id = jQuery('#edit_id').val();
var formula_id = jQuery('.select-formula').find(":selected").val();
var number_range = jQuery('.formula-number-range').find(':selected').val();

var select_formula = jQuery('.select-formula').find(':selected').val();
if(select_formula == ''){
	swal("","Select an Formula","");
	return false;
}

if(number_range == 'number'){
	var formula_num = jQuery('input[name="outcome-mapping-number"]').val();
	if(formula_num == ''){
		swal("","Enter Number","");
		return false;
	}
}else{
	var formula_start = jQuery('input[name="outcome-mapping-start"]').val();
	var formula_end = jQuery('input[name="outcome-mapping-end"]').val();

	var formula_range = formula_start+'-'+formula_end;
	if(formula_start == '' || formula_end == ''){
		swal("","Enter Start and End number","");
		return false;
	}
}

var outcome_id = jQuery('.select-formula-outcome').find(':selected').val();
if(outcome_id == ''){
	swal("","Select an Outcome","");
	return false;
}

jQuery('.feilds-edit-saves').text('Saving...');

var form_data = {
		quiz_id: quiz_id,
		formula_id: formula_id ,
		number_range: number_range,
		formula_num: formula_num,
		formula_range: formula_range,
		outcome_id: outcome_id,			
	}

jQuery.post(ajaxurl, {
	action: 'sqb_save_calculator_mapping',
	form_data: form_data,		
}, function(response) {	
	response = JSON.parse(response);	
	jQuery(".formula-mapping-popup").show().delay(3000).fadeOut();
	jQuery('.feilds-edit-saves').text('Save');
	sqb_load_formula_data(formula_id);


});
}

