						if(typeof get_html[index][val] != 'undefined'){
							var outcome_ids = get_html[index][val].outcome_ids;	 	
						}
					
						if (typeof outcome_ids !="undefined"){
							if (outcome_ids.indexOf(",") >  0){
								var outcomeids = outcome_ids.split(',');
								parent_selector.find(" .outcome-option-connect").trigger('click');	
								jQuery.each(outcomeids, function( index, value ) {	
									parent_selector.find("[data-answer-id ='"+val+"']").find(".outcome_result_list input[value='" + value + "']").prop('checked', true);
								});
							} else{					 
								parent_selector.find(" .outcome-option-connect").trigger('click');
								parent_selector.find("[data-answer-id ='"+val+"']").find(".outcome_result_list input[value='" + outcome_ids + "']").prop('checked', true);					 
							}
						} 	
