function sqb_get_pdf_data(outcome_id, show_modal=""){
	var quiztype = jQuery('#quiz_type_switch').val();
	SQBShowLoader();
jQuery.post(ajaxurl, {
	action: 'sqb_get_pdf_settings',
	outcome_id: outcome_id,   
}, function(response) {	
	if(show_modal == 1){
		jQuery('#pdf_download_modal').modal('show');
	}
	response = JSON.parse(response);
	if(response.pdf_html && response.pdf_html != 'NULL'){
		tinymce.get("pdf_html_body").setContent(response.pdf_html);
	} else{
		tinymce.get("pdf_html_body").setContent('<p><strong><span style="font-size: 12pt;" data-mce-style="font-size: 12pt;">Thank you for completing the quiz:<br></span> <br></strong>%%QUIZ_TITLE%%&nbsp;</p><h3><span style="font-size: 12pt;" data-mce-style="font-size: 12pt;">Here’s a breakdown of your results:</span></h3><ul><li><strong>Your Result:</strong> %%OUTCOME%%<br><br></li><li><strong>Your Responses:</strong> %%ANSWERS%%</li></ul><p>We hope this gives you valuable insights! If you have any questions or need more guidance, feel free to reach out.</p>');
	}

	if(response.pdf_id && response.pdf_id != 'NULL'){
		var home_url = jQuery('#get_home_url').val();
		var page_url = home_url+'/wp-admin/admin.php?page=sqb_create_pdf_content_page&id='+response.pdf_id;
		jQuery('.page_builder_edit_url').attr('href', page_url);

		//jQuery('.pdf-content-data select').val(response.pdf_id);

		//jQuery(".pdf-content-data select").select2("val", response.pdf_id);

		jQuery('.pdf-content-data select').val(response.pdf_id);
		jQuery('.pdf-content-data select').trigger('change.select2');

		if(response.pdf_id == '0'){
			jQuery('.page_builder_edit_url_outer').hide();
		}else{
			jQuery('.page_builder_edit_url_outer').show();
		}
	}
	SQBHideLoader();			
});	
}

function sqb_get_pdf_questions(quiz_id){

jQuery.post(ajaxurl, {
	action: 'sqb_get_all_questions',
	quiz_id: quiz_id,   
}, function(response) {	
	response = JSON.parse(response);
	var questionn_merge_tag = '';
	var i = 1;
	if(response != ''){
		questionn_merge_tag += '<li class="notification-header">Available Tags <i class="Personalize_question_close fa fa-times" aria-hidden="true"></i></li>';
		jQuery.each(response, function(index) {
			var info = '<div class="tool-tip"><i class="fa fa-info-circle" aria-hidden="true"></i> <div class="toll-tip-desc" style="width:265px;right:-175px;">'+response[index].question_title+'</div></div>';
			questionn_merge_tag += '<li class="addtoeditor" title="'+response[index].question_title+'">%%QUESTION_'+i+'%%</li>';
			questionn_merge_tag += '<li class="addtoeditor" title="'+response[index].question_title+'">%%QUESTION_'+i+'_SELECTED_ANSWERS%%</li>';
			i++;
		});
		
		if(questionn_merge_tag != ''){
			jQuery('.all_ques_merge_tag').html(questionn_merge_tag);
		}
	}

});	

}

function sqb_stripslashes (str) {

return (str + '').replace(/\\(.?)/g, function (s, n1) {
switch (n1) {
case '\\':
  return '\\';
case '0':
  return '\u0000';
case '':
  return '';
default:
  return n1;
}
});
}

