function sqb_save_automations(){

jQuery('.save_automation_btn').on('click',function(){
	var obj = this;
	var autoresponder_name = jQuery(this).attr('data-action-id');
	var key = '';
	var api_url = '';
	var api_secret = '';
	var api_keys = '';  
	var api_key = '';
	var client_id = '';
	var api_token = '';
	var api_id ='';
	var api_password ='';
	var client_id = '';
	var api_token = '';
	
	if(autoresponder_name == 'activecampaign'){
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		api_url = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_url"]').val();
		
		if(api_key == ''){
			sqb_sweet_message('',"Please API Key.","");
			return false;
		}
		if(api_url == ''){
			sqb_sweet_message('',"Please API URL.","");
			return false;
		}
		
	}else if(autoresponder_name == 'kartra'){
		api_id = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_id"]').val();
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		api_password = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_password"]').val();
		
		if(api_id == ''){
			sqb_sweet_message('',"Please APP ID.","");
			return false;
		}
		if(api_key == ''){
			sqb_sweet_message('',"Please API Key.","");
			return false;
		}

		if(api_password == ''){
			sqb_sweet_message('',"Please API Password.","");
			return false;
		}

	}else if(autoresponder_name == 'aweber'){

		api_keys = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_keys"]').val();
		
		if(api_keys == ''){
			sqb_sweet_message('',"Please API Key.","");
			return false;
		}
		
		
	}else if(autoresponder_name == 'drip'){
		client_id = jQuery('.'+autoresponder_name+'_save_model').find('input[name="client_id"]').val();
		api_token = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_token"]').val();
		
		
		if(client_id == ''){
			sqb_sweet_message('',"Please enter client ID.","");
			return false;
		}
		
		if(api_token == ''){
			sqb_sweet_message('',"Please enter API token.","");
			return false;
		}
		
	}else if(autoresponder_name == 'mailchimp'){
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		if(api_key == ''){
			sqb_sweet_message('',"Please enter API Key.","");
			return false;
		}
		
	}else if(autoresponder_name == 'convertkit'){
		
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		api_secret = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_secret"]').val();
		
		
		
		if(api_key == ''){
			sqb_sweet_message('',"Please enter API Key.","");
			return false;
		}
		
		
		if(api_secret == ''){
			sqb_sweet_message('',"Please enter API Secret.","");
			return false;
		}
	}else if(autoresponder_name == 'sendinblue'){
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		if(api_key == ''){
			sqb_sweet_message('',"Please enter API Key.","");
			return false;
		}
	}else if(autoresponder_name == 'getresponse'){
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		if(api_key == ''){
			sqb_sweet_message('',"Please enter API Key.","");
			return false;
		}
			
			
	}else if(autoresponder_name == 'mailerlite'){
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		if(api_key == ''){
			sqb_sweet_message('',"Please enter API Key.","");
			return false;
		}
			
			
	}else if(autoresponder_name == 'sendfox'){
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_token"]').val();
		if(api_key == ''){
			sqb_sweet_message('',"Please enter API Token.","");
			return false;
		}
			
			
	}else if((autoresponder_name == 'moosend') || (autoresponder_name == 'vbout') || (autoresponder_name == 'klaviyo') || (autoresponder_name == 'acumbamail') || (autoresponder_name == 'hubspot')){
		api_key = jQuery('.'+autoresponder_name+'_save_model').find('input[name="api_key"]').val();
		var alert_msg = "Please enter API Key.";
		if(autoresponder_name == 'acumbamail' || autoresponder_name == 'hubspot'){
			alert_msg = "Please enter auth token.";
		}
		if(api_key == ''){
			sqb_sweet_message('',alert_msg,"");
			return false;
		}
			
	}else{
		return false;
	}
	
	jQuery(this).text('Save....')
	jQuery.post(ajaxurl, {
		action: 'sqb_qutomation_save',
		api_key: api_key ,
		api_secret: api_secret,
		api_url: api_url,
		api_keys: api_keys,
		autoresponder_name: autoresponder_name,
		client_id: client_id,
		api_token: api_token,
		api_id:api_id,
		api_password : api_password
}, function(response) {
		
		response = JSON.parse(response);				
		jQuery(obj).text('Save');
		if(response.success){

			if(autoresponder_name == 'aweber'){
				jQuery('.aweber-saved-success').show();
				jQuery('.authorization_url').show();
				jQuery('.'+autoresponder_name+'_save_model').modal('hide');
				setTimeout(function(){
					jQuery('.aweber-saved-success').hide();
				}, 5000);
			}else{
				jQuery('.'+autoresponder_name+'_save_model').modal('hide');
			}
			

			var model_id = jQuery('.'+autoresponder_name+'_save_model').attr('id');
			jQuery('button[data-target="#'+model_id+'"]').text('Connected').addClass('btn-success');
			jQuery('button[data-target="#'+model_id+'"]').closest('li').find('.autoresonder_details_fields_outer').show();
			
			if(response.autoresponder_name){
				if(response.autoresponder_name == 'ACTIVECAMPAIGN'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.show_selected_type_data').html(response.data.auto_html_select);
					if(response.data.customFields_array_select){
						sqb_outcome_custom_field_id_select = '<a class="dropdown-item" href="javascript:void(0)" data-value="0">Select Field</a>'+response.data.customFields_array_select;
						jQuery('.sqb_outcome_custom_field_id_select').html(sqb_outcome_custom_field_id_select);
					}
					
				}else if(response.autoresponder_name == 'AWEBER'){
					
					jQuery("."+autoresponder_name+'_save_outer_div').find('.show_selected_type_data').html(response.data.auto_html_select);
					
				}else if(response.autoresponder_name == 'MAILCHIMP'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.show_selected_type_data').html(response.data.auto_html_select);
					
				}else if(response.autoresponder_name == 'DRIP'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.add_to_value_drip').html(response.data.auto_html_select);
					
				}else if(response.autoresponder_name == 'CONVERTKIT'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_sequence_outer').html(response.data.auto_html_sequence_select);
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_form_outer').html(response.data.auto_html_forms_select);
				}else if(response.autoresponder_name == 'SENDINBLUE'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_list_outer').html(response.data.lists);
				}else if(response.autoresponder_name == 'KARTRA'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_list_outer').html(response.data.lists);						
				}else if(response.autoresponder_name == 'GETRESPONSE'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_list_outer').html(response.data.lists);
				}else if(response.autoresponder_name == 'MAILERLITE'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_list_outer').html(response.data.lists);
				
				}else if(response.autoresponder_name == 'MOOSEND'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_list_outer').html(response.data.lists);
				}else if(response.autoresponder_name == 'SENDFOX'){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_list_outer').html(response.data.lists);
				}else if((response.autoresponder_name == 'VBOUT') || (response.autoresponder_name == 'KLAVIYO') || (response.autoresponder_name == 'ACUMBAMAIL') || (response.autoresponder_name == 'HUBSPOT')){
					jQuery("."+autoresponder_name+'_save_outer_div').find('.sqb_select_list_outer').html(response.data.lists);
				}
				
			}
		}else{
			sqb_sweet_message('',"Something wrong","");
		}	

		
		
	});
});
}





