function sqb_create_quiz_tabs_Validation(){

jQuery('.create_quiz_top_tabs_div li.nav-item').on('click','a', function (e) {
	
	if(e.target == e.currentTarget) {
		var current_tab_id = jQuery(e.target).attr("href"); // activated tab
	}else {
		var current_tab_id = jQuery(this).parents('li').find('a').attr("href"); // activated tab
	}	
	if(current_tab_id == '#Basic-Settings'){
		sqb_next_tab(current_tab_id);
		return ;
	}
	
	if(current_tab_id == '#Quiz-Screen-Settings'){
		var select_temp = jQuery('input[name="select_temp"]:checked').val();	
		if(select_temp == 'template9'){
			if(jQuery('.sqb_question_no.active .Quiz-Template9-inner').hasClass('sqb-template-bg-video-left') || jQuery('.sqb_question_no.active .Quiz-Template9-inner').hasClass('sqb-template-bg-video-right')){
				playSilentVideo(jQuery('.sqb_question_no.active .Quiz-Template9-left-side'));
			}
		}	
	}

	if(current_tab_id == '#Result-Screen-Settings'){
		var select_temp = jQuery('input[name="select_temp"]:checked').val();	
		if(select_temp == 'template9'){
			if(jQuery('.res_data_cont.active .Quiz-Template9-column-wrapper').hasClass('sqb-template-bg-video-left') || jQuery('.res_data_cont.active .Quiz-Template9-column-wrapper').hasClass('sqb-template-bg-video-right')){
				playSilentVideo(jQuery('.res_data_cont.active .outcome-Screen-Quiz-Template9-left-side'));
			}
		}	
	}

	if(current_tab_id == '#Start-Screen-Settings'){
		var select_temp = jQuery('input[name="select_temp"]:checked').val();	
		if(select_temp == 'template9'){
			if(jQuery('.template9_start_temp_outer').hasClass('sqb-template-bg-video-left') || jQuery('.template9_start_temp_outer').hasClass('sqb-template-bg-video-right')){
				playSilentVideo(jQuery('.Start-Screen-Quiz-Template9-left-side'));
			}
		}	
	}
	
	if(sqb_create_quiz_basic_tab_validation(current_tab_id)){
		
		
		if(current_tab_id == '#Quiz-Screen-Settings'){
			current_tab_id = 'Result-Screen-Settings';
			jQuery('#Result-Screen-Settings-tab').trigger('click');
			return false;
		}else if(current_tab_id == '#Formula-Screen'){
			sqb_next_tab('Quiz-Screen-Settings');
			return false;
			
		}else{current_tab_id = 'Basic-Settings';}
		sqb_next_tab(current_tab_id);
		return false;
	}
	
	if(sqb_create_quiz_display_tab_validation(current_tab_id)){
		current_tab_id = 'Basic-Screen-Settings';
		sqb_next_tab(current_tab_id);
		return false;	
	}
	
	if(current_tab_id == '#Start-Screen-Settings') {
		sqb_check_if_template5_selected('Start-Screen-Settings');
	}
	if(current_tab_id == '#Quiz-Screen-Settings') {
		sqb_check_if_template5_selected('Quiz-Screen-Settings');
	}
	if(current_tab_id == '#Result-Screen-Settings') {
		sqb_check_if_template5_selected('Result-Screen-Settings');
	}
	if(current_tab_id == '#Opt-Screen-Settings') {
		sqb_check_if_template5_selected('Opt-Screen-Settings');
	}
	
	// when click on previe tab then load template html agin
	if(current_tab_id == '#preview-Screen-Settings'){
		var start_temp_static_div = jQuery('.start_temp_static_div').html();
		var optin_temp_static_div = jQuery('.optin_temp_static_div').html();
		var result_temp_static_div = jQuery('.result_temp_static_div').html();
		jQuery('.start_template_html_preview_outer').html(start_temp_static_div);
		jQuery('.optin_template_html_preview_outer').html(optin_temp_static_div);
		jQuery('.result_template_html_preview_outer').html(result_temp_static_div);		
		
	}
	
	if(current_tab_id == '#create_quiz_advance'){
		if((jQuery('#edit_id').val() == '') || (jQuery('#edit_id').val() == 0)){
			swal('',"Please Save the Quiz","");
			return false;
		}

		if(jQuery('.result_template_html_preview_outer .res_data_cont').length == 0 && jQuery('input[name=quiz_type]:checked').val() != 'poll'){
			jQuery('.scoring-outcome-empty-message').show();
		}else{
			jQuery('.scoring-outcome-empty-message').hide();
		}

		if(jQuery('.Question_temp_static_div .sqb_question_no').length == 0 && jQuery('input[name=quiz_type]:checked').val() != 'form'){
			jQuery('.scoring-question-empty-message').show();
		}else{
			jQuery('.scoring-question-empty-message').hide();
		}
	}
	
	
	sqb_next_tab(current_tab_id);
	
	});
}


function sqb_create_quiz_basic_tab_validation(current_tab_id = ''){

var validation_status = false;

if(current_tab_id == '#Basic-Settings'){
	return validation_status;
}

var quiz_name = jQuery("input#quiz_name").val();
if(quiz_name == ''){
	validation_status = true;
	var msg = "Give the Quiz a Name";
	sqb_sweet_message('',msg,'');
	return validation_status;
	
}

var quiz_desc = jQuery("#quiz_desc").val();
if(quiz_desc == ''){
	validation_status = true;
	var msg = "Enter Quiz Description";
	sqb_sweet_message('',msg,'');
	return validation_status;
	
}

if(current_tab_id == '#Quiz-Screen-Settings'){

	if(jQuery('.result_template_html_preview_outer .res_data_cont').length == 0 && jQuery('input[name=quiz_type]:checked').val() == 'personality'){
		validation_status = true;
		var msg = "You need to create at least one outcome / result";
		sqb_sweet_message('',msg,'');
		
	}	else if(jQuery('.result_template_html_preview_outer .res_data_cont').length == 0 && jQuery('input[name=quiz_type]:checked').val() == 'poll' && jQuery('input[name="show_results"]').val() == 'redirect-to-outcome'){
		validation_status = true;
		var msg = "You need to create at least one outcome / result";
		sqb_sweet_message('',msg,'');
		
	}	
	
	if((jQuery('.result_template_html_preview_outer .res_data_cont input#outcome_id').val() == '')  && jQuery('input[name=quiz_type]:checked').val() == 'personality'){
		validation_status = true;
		var msg = "Please save outcome first";
		sqb_sweet_message('',msg,'');
		
	}

}else if(current_tab_id == '#Formula-Screen'){
	var check_one_question_is_not_save = true;
	if(jQuery('.left_side_question_list ul li').length < 1){
		validation_status = true;
		var msg = "To create a formula, you need to add at least 1 question.";
		sqb_sweet_message('',msg,'');
	}else{
		jQuery('.sqb_questions_wrapper .question_div_outer').each(function(){
			var formula_question_id = jQuery(this).find('.sqb_question_enable_drag_drop').attr('data-id');
			if(isNaN(formula_question_id)){
			}else{
				check_one_question_is_not_save = false;
			}
			
		});
		
	}
	
	if(check_one_question_is_not_save){
			validation_status = true;
			var msg = "To create a formula, you need to add at least 1 question.";
			sqb_sweet_message('',msg,'');
	}
}
 
return validation_status;
}




function sqb_create_quiz_display_tab_validation( current_tab_id = ''){

var validation_status = false;

if(current_tab_id == '#Basic-Screen-Settings'){
	return validation_status;
}


var question_display = jQuery('input[type="radio"][name="question_display"]:checked').val();
var number_of_question  = jQuery('input[name="number_of_question"]').val();
if(question_display == 'survey' && (number_of_question == '')){
	validation_status = true;
	var msg = " Enter total number of questions to be displayed";
	sqb_sweet_message('',msg,'');
	return validation_status;
	
}

var quiz_pagination = jQuery('input[type="radio"][name="quiz_pagination"]:checked').val();
var question_per_page  = jQuery('input[name="question_per_page"]').val();
if(quiz_pagination == 'limited' && (question_per_page == '')){
	validation_status = true;
	var msg = " Enter number of Question";
	sqb_sweet_message('',msg,'');
	return validation_status;
}

var show_opt_screen = jQuery('input#show_opt_screen').prop('checked');
var user_opt_in_redirect  = jQuery('select#user_opt_in_redirect option:selected').val();	
var user_opt_in_redirect_url  = jQuery('input#user_opt_in_redirect_url').val();	
if(show_opt_screen && (user_opt_in_redirect == 'opt_in_redirect_specific_page') && (user_opt_in_redirect_url == '')){
	validation_status = true;
	var msg = " Enter Redirect URL";
	sqb_sweet_message('',msg,'');
	return validation_status;
	
}


return validation_status;

}

