function sqb_save_redirect(){	
	SQBShowLoader();
	jQuery('.redirect-message').remove();
	var outcome_msg = '';
	var count = 1;
	var show_redirect = '';
	var url = jQuery('input.get-site-url').val(); 
	var send_user_details = jQuery('#send_user_details').prop('checked');
	jQuery("#outcome_modal .outcome_modal_body .outcome_modal_body_inn").each(function(index, val){		 				
		var get_checked = jQuery(this).find('input[type="radio"]:checked').val();

		var data_id = jQuery(this).data("id"); 	 

		var outcome_div_id = jQuery(this).attr("id"); 	 
		//var outcome_redirect = jQuery("#"+outcome_div_id+" .outcome_redirect").val();	
		var outcome_redirect = jQuery(this).find(".outcome_redirect").val();	
		outcome_redirect = outcome_redirect.replace(/(^\w+:|^)\/\//, '');
		jQuery(this).find(".outcome_redirect").val(outcome_redirect);

		var outcome_screen = jQuery("#"+outcome_div_id+" .outcome_redirect_out input:checked").val();		  
		var outcome_id = jQuery("#"+outcome_div_id+" .outcome_cls").val();	
		
		if(get_checked == 'redirect'){
			if(outcome_redirect == ''){
				swal('Please enter the URL.');
			}

			if(send_user_details == true){
				if (outcome_redirect.indexOf('email') === -1) {
				    outcome_redirect += '?&email=%%EMAILID%%';
				}
				if (outcome_redirect.indexOf('outcome_title') === -1) {
				    outcome_redirect += '&outcome_title=%%OUTCOMETITLE%%';
				}
				if (outcome_redirect.indexOf('first_name') === -1) {
				    outcome_redirect += '&first_name=%%FIRSTNAME%%';
				}
				if (outcome_redirect.indexOf('user_id') === -1) {
				    outcome_redirect += '&user_id=%%USERID%%';
				}
				if (outcome_redirect.indexOf('quiz_id') === -1) {
				    outcome_redirect += '&quiz_id=%%QUIZID%%';
				    jQuery('.user-details-message').show();
				}
				if (outcome_redirect.indexOf('rank') === -1) {
				    outcome_redirect += '&rank1=%%RANK1ID%%&rank2=%%RANK2ID%%&rank3=%%RANK3ID%%';
				}
			}else{
				/*var cleanedUrl = outcome_redirect.replace(/&&/g, '&');
			    var urlParts = cleanedUrl.split('?');
			    if (urlParts.length === 2) {
			        var baseUrl = urlParts[0];
			        var queryString = urlParts[1];
			        var paramsToRemove = ['email', 'outcome_title', 'first_name', 'user_id', 'quiz_id'];
			        var keyValuePairs = queryString.split('&');
			        var filteredKeyValuePairs = keyValuePairs.filter(function(keyValuePair) {
			            var parts = keyValuePair.split('=');
			            return parts.length === 2 && paramsToRemove.indexOf(parts[0]) === -1;
			        });
			        var outcome_redirect = baseUrl + '?' + filteredKeyValuePairs.join('&');
			        jQuery(this).find(".outcome_redirect").val(outcome_redirect);
			    }*/
			    outcome_redirect = outcome_redirect.split('?')[0];
			}
			jQuery(this).find(".outcome_redirect").val(outcome_redirect);

			var hash = outcome_redirect.substring(outcome_redirect.indexOf('?')+1);		

			if(hash == 'email=%%EMAILID%%&first_name=%%FIRSTNAME%%&outcome_title=%%OUTCOMETITLE%%'){
				outcome_msg += '';	
			}else{

				if(outcome_redirect == ''){
					outcome_msg += '<p><strong style="color:#f05451">Outcome '+count+': </strong><br>'+url+'/?email=%%EMAILID%%&first_name=%%FIRSTNAME%%&outcome_title=%%OUTCOMETITLE%%</p>';
				}else{
					outcome_msg += '<p><strong style="color:#f05451">Outcome '+count+': </strong><br> https://'+outcome_redirect+'/?email=%%EMAILID%%&first_name=%%FIRSTNAME%%&outcome_title=%%OUTCOMETITLE%%</p>';
				}	
				
				show_redirect = 'display:none';
			}
		}
		jQuery.post(ajaxurl, {
				action: 'sqb_outcometemp',
				security: SQBVar.sqbSaveOutcomeTag,
				id: outcome_id ,
				outcome_redirect: outcome_redirect ,
				outcome_screen: outcome_screen ,
				outcome_action: "redirectsave",					 
		}, function(response) {		
			SQBHideLoader();		 
			jQuery('#'+data_id).find('.outcome_screen').val(outcome_screen);
			jQuery('#'+data_id).find('.outcome_redirect').val(outcome_redirect);
			jQuery('.outcome_modal_body_inn .saved_data_msg').css("display","inline-block");
			setTimeout(function(){ jQuery('.outcome_modal_body_inn .saved_data_msg').css("display","none"); }, 5000);
		});
		count++;	
	}); 

	if(outcome_msg == ''){
		show_redirect = 'display:none';
	}else{
		show_redirect = 'display:block';
	}

	/*var html = '<div class="shortocde_details redirect-message mt-4" style="'+show_redirect+'"><p>Do you want SQB to send these fields in query string to the redirect URL? <br> <strong> email, first_name, outcome_title</strong> </p><p>If yes, replace the redirect URL you have above with these: </p> '+outcome_msg+'</div>'	
	jQuery('.modal-body.outcome_modal_body').append(html);*/
}


