function sqb_opacity_reverse(opacity_val){
	    var opacity_cal = 1 - opacity_val;
	    opacity_cal = opacity_cal.toFixed(2);
	    return opacity_cal;
	}
function get_background_image_opacity(sqb_bg_image){
var sqb_bg_image_linear_gred = sqb_bg_image.replace('linear-gradient(',',');
var sqb_bg_image_splited = sqb_bg_image_linear_gred.split(',');
var sqb_bg_image_arr = jQuery.makeArray(sqb_bg_image_splited);
var opacity_range = sqb_bg_image_arr[4];
if(parseFloat(sqb_bg_image_arr[4]) < 0.1){
	var sqb_bg_image_opacity = false;
} else {
	var sqb_bg_image_opacity = sqb_bg_image_arr[1]+','+sqb_bg_image_arr[2]+','+sqb_bg_image_arr[3]+','+opacity_range;
}
return sqb_bg_image_opacity;
}

