function sqbDeleteQuiz(quiz_id = 0){

if(quiz_id == '' || quiz_id == 0){
	return false;
}

	swal({
	title: "Are you sure you want to delete ?",
	text: "You cannot recover the settings.",
	//type: "warning",
	showCancelButton: true,
	showCloseButton: true,
	confirmButtonColor: "#DD6B55",
	confirmButtonText: "Yes, Delete!",
	customClass: '',
	
	}).then((result) => {  
		if (result.value) {
			SQBShowLoader();
			jQuery.post(ajaxurl, {
			action: 'sqb_delete_quiz_by_id',
			quiz_id: quiz_id ,
						 
			}, function(response) {		
				swal('','Quiz Deleted',"success");
				SQBHideLoader();
				location.reload();		 
				
			});
			
			
			
		}
	});



}

