function set_formula_title(){
var max = 0;
jQuery('#sqb_formula_list table tbody tr').each(function() {
  var value = parseInt(jQuery(this).attr('data-row-count'));
  max = (value > max) ? value : max;
});
var formula_no = max+1;
jQuery('.formula_title').html('<strong>Title:</strong> FORMULA '+formula_no);
}



