jQuery('body').on('click','.formula-variable-item',function(e){
	e.stopImmediatePropagation();
	var formula_sign =jQuery(this).data('formula-sign');
	jQuery("span.formula-variable-item").removeClass("active");
	jQuery(this).addClass("active");

	if(formula_sign == 'if'){
		jQuery('.show-messages').show().html('This expression (x) is a conditional expression. If the value of "x" is true, the result will be "y", otherwise it\'ll be "z". <br>For e.g. (Q1&lt;Q2) ? Q4:Q3');
		return false;
	}else if(formula_sign == 'ifand'){
		jQuery('.show-messages').show().html('This expression (X AND Y) is a conditional expression. If both X and Y are true, the result will be "y", otherwise it\'ll be "z". <br>For e.g. ((Q1&lt;Q2) && (Q3&lt;Q4)) ? 20:10');
		return false;
	}else if(formula_sign == 'ifor'){
		jQuery('.show-messages').show().html('This expression (X OR Y) is a conditional expression. If X is true OR Y is true (or both are true), the result will be "y", otherwise (if both are false) it\'ll be "z". <br>For e.g. ((Q1&lt;Q2) || (Q3&lt;Q4)) ? 20:10 ');
		return false;
	}else if(formula_sign == 'round'){
		jQuery('.show-messages').show().html("Value rounded to the nearest integer, Math.round(x). <br>For e.g. Math.round(Q1/Q2)");
		return false;
	}else if(formula_sign == 'floor'){
		jQuery('.show-messages').show().html("The Math.floor() function returns the largest integer less than or equal to a given number. <br>For e.g. Math.floor(Q1/Q2)");
		return false;
	}else if(formula_sign == 'ceil'){
		jQuery('.show-messages').show().html("The Math.ceil() function always rounds a number up to the next largest integer. <br>For e.g. Math.ceil(Q1/Q2)");
		return false;
	}else if(formula_sign == 'log'){
		jQuery('.show-messages').show().html("The natural logarithm (base e) of the given number. If the number is negative, NaN is returned. <br>For e.g. Math.log(Q1/Q2)");
		return false;
	}else{
		jQuery('.show-messages').hide().empty();
		var formula_sign_text = jQuery('.formula-content-right textarea');
		formula_sign_text.val(formula_sign_text.val() + formula_sign);
		validate_expression();
	}
});

