function validate_expression(){
var question_count = jQuery('.left_side_question_list ul li').length;
//var question_count = jQuery('#Formula-Screen .formula-question-list .formula-question').length;
var expression = jQuery('#name_formula').val();

var formula_count = jQuery('#sqb_formula_list tbody tr').length;
for(i=0;i<=formula_count;i++){
	jQuery('#sqb_formula_list tbody tr').each(function(){
		var formula_id = jQuery(this).attr('data-formulaid');
		if(expression.indexOf("[FORMULA id="+formula_id+"]") != -1){
			var formula = jQuery(this).find('.data-formula-name-'+formula_id).text();	
			expression = expression.replaceAll("[FORMULA id="+formula_id+']', '('+formula+')');
		}
	});
}

for(i=0;i<=question_count;i++){
	expression = expression.replaceAll("Q"+i+"W", 1);
	expression = expression.replaceAll("Q"+i+"H", 1);
	expression = expression.replaceAll("Q"+i, 1);
}
if (expression != '') {
	try {
		var result = eval(expression);
		//jQuery('.validation_message').show().html('Expression is Valid');
		jQuery('.validation_message').hide();
	}
	catch (e) {
		jQuery('.validation_message').show().html('This expression is invalid.');
	}
}
else {
	jQuery('.validation_message').show().html('Sorry the formula cannot be empty. Please enter an expression.');
}
}

