function applyGlobalLevelSettings() {
	var isChecked = jQuery('#sqb_enable_global_setting_style').prop('checked');
    if (isChecked) {
		setGlobalSettingLevelValues();
    }else{
		setQuizSettingLevelValues();
    }
}

function globalLevelFields(){
	
	var isChecked = jQuery('#sqb_enable_global_setting_style').prop('checked');
	if (isChecked) {
		setGlobalSettingLevelValues();
	}else{
		setQuizSettingLevelValues(false);
	}
	

	jQuery('#sqb_enable_global_setting_style').change(function() {

		var select_temp = jQuery('input[name="select_temp"]:checked').val();
		var current_obj = this;

		if(select_temp == 'template9'){
			swal("","Sorry, currently we don't support global settings for template 9.","");
			return false;
		}

		// Check if the checkbox is checked
		if (jQuery(this).is(':checked')) {

			swal({
				title: "Are you sure you want to enable global style settings?",
				text: "If yes, it will take all customizer values globally for all quizzes.",
				//type: "warning",
				showCancelButton: true,
				showCloseButton: true,
				confirmButtonColor: "#4aef94",
				confirmButtonText: "Yes",
				customClass: '',
				
			}).then((result) => {
				if (result.value) {
					jQuery('.customizer-heading-text').text('Global Style');
					setGlobalSettingLevelValues();
					jQuery('.setting-level-global').show();
					jQuery('.setting-level-quiz').hide();
					jQuery('.create-quiz-block').addClass('sqb-gls-global').removeClass('sqb-gls-quiz');
				}else{
					jQuery(current_obj).prop('checked',false);
				}
			});
			
		} else {
			setQuizSettingLevelValues();
			jQuery('.customizer-heading-text').text('Quiz Style');
			jQuery('.setting-level-global').hide();
			jQuery('.setting-level-quiz').show();
			jQuery('.create-quiz-block').addClass('sqb-gls-quiz').removeClass('sqb-gls-global');
		}
	});

	jQuery('.sqb_gl_style_color_field').each(function() {
		jQuery(this).colorpicker().on('changeColor', function() {
			if(!jQuery('#sqb_enable_global_setting_style').prop('checked')){
				return false
			}
			sqb_global_setting_call_apply();		
			var get_val = jQuery(this).colorpicker('getValue');
			var css_var  = jQuery(this).closest('.gl-style-global').attr('data-cssvar');
			if(css_var == 'sqb_global_background_color'){
				jQuery("body").get(0).style.setProperty("--sqb_global_background", get_val+'');
			}
			jQuery("body").get(0).style.setProperty("--"+css_var, get_val);
		});
	});

	jQuery('.sqb_gl_style_slider_field').each(function() {
		jQuery(this).bootstrapSlider().change(function() {
			if(!jQuery('#sqb_enable_global_setting_style').prop('checked')){
				return false
			}
			sqb_global_setting_call_apply();
			var css_var  = jQuery(this).closest('.gl-style-global').attr('data-cssvar');
			var prefix = jQuery(this).attr('data-fieldprefix');
			jQuery("body").get(0).style.setProperty("--"+css_var, this.value+prefix);
		});
	});

	jQuery('.sqb_gl_style_font_field').each(function() {
		jQuery(this).on('change',function(){
			if(!jQuery('#sqb_enable_global_setting_style').prop('checked')){
				return false
			}
			sqb_global_setting_call_apply();
			var css_var  = jQuery(this).closest('.gl-style-global').attr('data-cssvar');
			jQuery("body").get(0).style.setProperty("--"+css_var, this.value);
			var font_url = 'https://fonts.googleapis.com/css2?family='+this.value;
								var stylesheet = jQuery("<link>", {
									rel: "stylesheet",
									type: "text/css",
									href: font_url
								});
								stylesheet.appendTo("head");
		});
	});

}

function getGlobalSettingLevelValues(){
	var object = {};
	
	jQuery('.sqb_gl_style_field').each(function(index, element) {
		
		var id = jQuery(this).attr('id');
		var type = jQuery(this).attr('data-fieldtype');
		var name = jQuery(this).attr('data-fieldname');

		if(type == 'color' || type == 'slider' || type == 'font' || type == 'media'){
			object[name] = jQuery('#'+id).val();
		}
	});
	
	return object;
}

function setGlobalSettingLevelValues(){
	jQuery('.create-quiz-block').addClass('sqb-gls-global').removeClass('sqb-gls-quiz');
	jQuery('.sqb_gl_style_field').each(function(index, element) {
		
		var id = jQuery(this).attr('id');
		var type = jQuery(this).attr('data-fieldtype');
		var name = jQuery(this).attr('data-fieldname');
		var css_var  = jQuery(this).closest('.gl-style-global').attr('data-cssvar');
		var prefix = jQuery(this).attr('data-fieldprefix');

		if(type == 'slider' ){
			var val = jQuery('#'+id).val();
			jQuery("body").get(0).style.setProperty("--"+css_var, val+prefix);
		}else if(type == 'color' || type == 'font'){
			var val = jQuery('#'+id).val();
			if(css_var == 'sqb_global_background_color'){
				jQuery("body").get(0).style.setProperty("--sqb_global_background", val+'');
			}
			jQuery("body").get(0).style.setProperty("--"+css_var, val+'');
		}else if(type == 'media'){
			var val = "linear-gradient(rgba(239,243,245,0.10),rgba(239,243,245,0.10)),url('"+jQuery('#'+id).val()+"')";
			jQuery("body").get(0).style.setProperty("--"+css_var, val);
		}
		
	});
}

function setQuizSettingLevelValues(isReq = true){

	if(isReq){
		jQuery('.sqb_gl_style_field').each(function(index, element) {
			
			var id = jQuery(this).attr('id');
			var type = jQuery(this).attr('data-fieldtype');
			var name = jQuery(this).attr('data-fieldname');
			var prefix = jQuery(this).attr('data-fieldprefix');
			name = name.replace('gl_', 'sqb_global_temp_');
			var css_var  = jQuery(this).closest('.gl-style-global').attr('data-cssvar');
			if(type == 'slider' ){
				var val = jQuery('#'+name).val();
				jQuery("body").get(0).style.setProperty("--"+css_var, val+prefix);
			}else if(type == 'color' || type == 'font' || type == 'media'){
				var val = jQuery('#'+name).val();
				
				if(name == 'sqb_global_temp_background_color'){
					if(val == undefined){
						var val = jQuery('#sqb_global_temp_background').val();

						var select_temp = jQuery('input[name="select_temp"]:checked').val();
						if(select_temp == 'template6' || select_temp == 'template8'){
							var val = jQuery('#sqb_global_background_color').val();
						}
					}
					jQuery("body").get(0).style.setProperty("--sqb_global_background", val+'');
				}
				jQuery("body").get(0).style.setProperty("--"+css_var, val+'');
				
			}
		});
	}
	jQuery('.create-quiz-block').addClass('sqb-gls-quiz').removeClass('sqb-gls-global');
}

