jQuery(document).on('click','.global-ItemIcon,.sqb_closed_global_customizer_opiton',function(){
	
	jQuery(this).closest('.global-Customizer-item').siblings().find('.globalInnerOptions').hide();
	jQuery(this).closest('.global-Customizer-item').find('.globalInnerOptions').toggle();
	
});
jQuery(document).on('click','.sqb_global_customizer_option_enable_btn',function(){
	if(jQuery(this).prop('checked')){
		
		jQuery(this).closest('.inner_template_style_box').find('.sqb_global_customizer_options').show('slow');
	}else{
		jQuery(this).closest('.inner_template_style_box').find('.sqb_global_customizer_options').hide('slow');
		if(jQuery(this).val() == 'selected_question_ans_color'){
			jQuery('span.sqbOpitionSelected').attr('style','');
		}
	}
	
	sqb_global_setting_call_apply();
});

jQuery(document).on('click','.sqb_global_customizer_option_enable_outer_style_btn',function(){
	if(jQuery(this).prop('checked')){
		jQuery('.sqb_template7_selected #Start-Screen-Settings .Template-Customize-content .quiz-card-outer-gray.start_temp_static_div').removeClass('sqb_disable_background');
		
		jQuery('.sqb_template7_selected #Outcome-Display .quiz_result_inn .outcome-section').removeClass('sqb_disable_background');
		jQuery('.sqb_template7_selected #Quiz-Screen-Settings .question_div_inner .question-screen').removeClass('sqb_disable_background');
		jQuery('.sqb_template7_selected #Opt-Screen-Settings .quiz-card-outer-gray').removeClass('sqb_disable_background');
		jQuery('.sqb_template7_selected #Opt-Screen-Settings .quiz-card-outer-gray .optin_template_html_preview_outer').addClass('sqb_disable_background');
		
		jQuery('.start_temp_outer, .result_temp_outer, .sqb_question_enable_drag_drop , .optin_temp_static_div .quiz_comon_template').css('border','none');
		jQuery('#sqb_background_status').val('Y');
	} else {
		jQuery('.sqb_template7_selected #Start-Screen-Settings .Template-Customize-content .quiz-card-outer-gray.start_temp_static_div').addClass('sqb_disable_background');
		
		jQuery('.sqb_template7_selected #Outcome-Display .quiz_result_inn .outcome-section').addClass('sqb_disable_background');
		jQuery('.sqb_template7_selected #Quiz-Screen-Settings .question_div_inner .question-screen').addClass('sqb_disable_background');
		jQuery('.sqb_template7_selected #Opt-Screen-Settings .quiz-card-outer-gray').addClass('sqb_disable_background');
		jQuery('.sqb_template7_selected #Opt-Screen-Settings .quiz-card-outer-gray .optin_template_html_preview_outer').addClass('sqb_disable_background');
		
		jQuery('.start_temp_outer, .result_temp_outer, .sqb_question_enable_drag_drop , .optin_temp_static_div .quiz_comon_template').css('border','1px solid #ddd');
		jQuery('#sqb_background_status').val('N');
		
		if(jQuery('#sqb_global_temp_background_image_enable').is(':checked')) {
			jQuery('#sqb_global_temp_background_image_enable').trigger("click");
		}
		if(jQuery('#sqb_global_temp_opacity_enable').is(':checked')) {
		jQuery('#sqb_global_temp_opacity_enable').trigger("click");
		}
		if(jQuery('#sqb_global_temp_background_enable_template7').is(':checked')) {
		jQuery('#sqb_global_temp_background_enable_template7').trigger("click");
		}
	}
	sqb_global_setting_call_apply();
});

jQuery(document).on('click','input[name="sqb_enable_global_setting_each_screen"]',function(){
	var current_obj = this;
	if(jQuery(this).prop('checked')){
		
		swal({
			title: "Are you sure you want to enable quiz style settings?",
			text: "This way you won't have to customize each screen individually.",
			//type: "warning",
			showCancelButton: true,
			showCloseButton: true,
			confirmButtonColor: "#4aef94",
			confirmButtonText: "Yes",
			customClass: 'sqb_enable_global_sweet_box',
			
		}).then((result) => {
			if (result.value) {
				jQuery('.tab-content#Quiz-Settings-TabContent .tab-pane.Quiz-Settings-TabContent_inner_first').addClass('sqb_global_theme_enable_each_template');
				//jQuery('.sqb_global_theme_enable_hide_customizer').hide();
				jQuery('.sqb_global_theme_enable_show_customizer').show();
				//sqb_global_setting_call_apply();
				jQuery('.global-Customizer-inner').show();
				jQuery('.global-Customizer-options').addClass('sqb_global_theme_sticky_enable');
				sqb_global_setting_options_screen_customizer_set_values();
				set_global_values();
				jQuery('.sqb_loading_wrapper').show();
				setTimeout(function() {
					tinymce.remove(".sqb_tiny_mce_editor");
					sqb_tiny_mce_editor();
					jQuery('.sqb_loading_wrapper').hide();
				}, 1000);
				jQuery('.create-quiz-block').addClass('sqbg-on');
				
			}else{
				jQuery(current_obj).prop('checked',false);
				jQuery('.global-Customizer-options').removeClass('sqb_global_theme_sticky_enable');
			}
		});
	
	}else{
		jQuery('.create-quiz-block').removeClass('sqbg-on');
		jQuery('.sqb_global_theme_enable_hide_customizer').show();
		jQuery('.sqb_global_theme_enable_show_customizer').hide();
		jQuery('.global-Customizer-inner').hide();
		jQuery('.tab-content#Quiz-Settings-TabContent .tab-pane.Quiz-Settings-TabContent_inner_first').removeClass('sqb_global_theme_enable_each_template');
		sqb_global_setting_call_apply();
		jQuery('.global-Customizer-options').removeClass('sqb_global_theme_sticky_enable');

		jQuery('.sqb_loading_wrapper').show();
		setTimeout(function() {
			
			//tinymce.remove();
			tinymce.remove(".sqb_tiny_mce_editor");
			sqb_tiny_mce_editor();
			jQuery('.sqb_loading_wrapper').hide();
		}, 1000);

	}
});

