function sqb_get_global_theme_style_values(screen_status  = 'N'){  

 var temp_global_view_layout = [];
 var start_screen_global_style_dynamic = '';
 var question_screen_global_style_dynamic   = '';
 var outcome_screen_global_style_dynamic = '';
 var opt_screen_global_style_dynamic = '';
 var temp_values_global_style_dynamic = '';
 
 temp_global_view_layout.push({
	'screen_name':'start_screen',
	'mobile_css_style':encodeURIComponent(jQuery("#start_screen_global_style_dynamic").html()),
	'screen_status':screen_status,
	'custom_values':'',
	'type':'global',
	});
	
	temp_global_view_layout.push({
	'screen_name':'question_screen',
	'mobile_css_style':encodeURIComponent(jQuery("#question_screen_global_style_dynamic").html()),
	'screen_status':screen_status,
	'custom_values':'',
	'type':'global',
	});
	
	temp_global_view_layout.push({
	'screen_name':'outcome_screen',
	'mobile_css_style':encodeURIComponent(jQuery("#outcome_screen_global_style_dynamic").html()),
	'screen_status':screen_status,
	'custom_values':'',
	'type':'global',
	});
	
	temp_global_view_layout.push({
	'screen_name':'opt_screen',
	'mobile_css_style':encodeURIComponent(jQuery("#opt_screen_global_style_dynamic").html()),
	'screen_status':screen_status,
	'custom_values':'',
	'type':'global',
	});
	
	temp_global_view_layout.push({
	'screen_name':'global_screen_values',
	'mobile_css_style':encodeURIComponent(jQuery("#temp_values_global_style_dynamic").html()),
	'screen_status':screen_status,
	'custom_values':'',
	'type':'global',
	});
	
	
 
 return temp_global_view_layout;
 
}


function sqb_get_pages_posts_url_list_html(tab_id){
jQuery('ul.sqb_form_selected_urls').empty();
jQuery('ul.sqb_selected_urls').empty();
jQuery('ul.sqb_popup_hidden_shortcode_selected_urls').empty();
jQuery('ul.sqb_select_urls li').removeClass('active_page_posts_url');
jQuery('ul.sqb_form_select_urls li').removeClass('active_page_posts_url');
	var quiz_id = jQuery("#edit_id").val();
	var quiz_type = jQuery('input[name="quiz_type"]:checked').val();
	SQBShowLoader();		
	jQuery.post(ajaxurl, {
			action: 'sqb_get_pages_posts_url_list_html',
			quiz_id: quiz_id,   
			tab_id: tab_id,   
			
	}, function(response) {		 
		SQBHideLoader();
		response = JSON.parse(response);
		jQuery('ul.sqb_popup_hidden_shortcode_selected_urls').empty();
		if(response.html){
			jQuery('.sqb_select_urls.sqb_pages_posts_list').html(response.html);
			jQuery('ul.sqb_selected_urls').empty();
			if(jQuery(document).find('ul.sqb_select_urls li.active_page_posts_url').length == 0){
				jQuery('ul.sqb_selected_urls').append('<li class="no-page-select">No Page selected</li>');
				jQuery('ul.sqb_popup_hidden_shortcode_selected_urls').append('<li class="no-page-select">No Page selected</li>');
			}else{
				jQuery(document).find('ul.sqb_select_urls li.active_page_posts_url').each(function(){
					var url_id = jQuery(this).attr('data-id');
					var page_url = jQuery(this).attr('data-value');
					jQuery('ul.sqb_selected_urls').append('<li data-id='+url_id+' data-value='+page_url+'>'+page_url+'</li>');
					jQuery('ul.sqb_popup_hidden_shortcode_selected_urls').append('<li data-id='+url_id+' data-value='+page_url+'><a href="..'+page_url+'" target="_blank">'+page_url+'</a></li>');
					jQuery(document).find('ul.sqb_select_urls li').css('cursor','pointer');
				});
			}

			

			if(quiz_type == 'form'){

				var checked_val = jQuery('input[name="popup_type"]:checked').val();
				if(checked_val == 'popup'){
					jQuery('.sqb_show_selected_page_popup').hide();
				}else{
					jQuery('.sqb_show_selected_page_popup').show();
				}
				jQuery('.sqb_form_select_urls.sqb_form_pages_posts_list').html(response.html);
				jQuery(document).find('ul.sqb_form_select_urls li.active_page_posts_url').each(function(){
					var url_id = jQuery(this).attr('data-id');
					var page_url = jQuery(this).attr('data-value');
					jQuery('ul.sqb_form_selected_urls').append('<li data-id='+url_id+' data-value='+page_url+'>'+page_url+'</li>');
					jQuery(document).find('ul.sqb_form_select_urls li').css('cursor','pointer');
				});

				jQuery('ul.sqb_form_shortcode_selected_urls').empty();

				jQuery('.sqb_form_hidden_shortcode_selected_urls').html(response.html);
				
				jQuery(document).find('ul.sqb_form_hidden_shortcode_selected_urls li.active_page_posts_url').each(function(){
					var url_id = jQuery(this).attr('data-id');
					var page_url = jQuery(this).attr('data-value');
					jQuery('ul.sqb_form_shortcode_selected_urls').append('<li data-id='+url_id+' data-value='+page_url+'>'+page_url+'</li>');
					
				});
			}
		}			
	});
}

