function sqb_import_quiz(){
  var input_type = jQuery('#frmzipImport').find('input[name="zip_file"]');
  var files = jQuery(input_type)[0].files;
  
  if(files.length < 1 ){
	  swal('Please select a zip file');
	  return false;
  }
  
  SQBShowLoader();
  var form = jQuery('#frmzipImport')[0];
  var varform = new FormData(form);
  varform.append("action", "sqb_import_zip");
  varform.append("security", SQBVar.sqb_import);
  sqbImportzipfile(varform);
}

function sqbImportzipfile(varform) {


jQuery.ajax({
	type: "POST",
	url: ajaxurl,
	dataType: "JSON",
	data: varform,
	processData: false,
	contentType: false,
	cache: false,
	beforeSend: sqbonLoadingzip,
	success: sqbonSuccesZipImport,
	crossDomain:true
});
}

function sqbonLoadingzip() {
}

function sqbonSuccesZipImport(data, status) {
jQuery('#frmzipImport').trigger("reset");
swal('',data.message,"success");
SQBHideLoader();
location.reload();
}

function sqb_getUrlVars()
{
var vars = [], hash;
var hashes = window.location.href.slice(window.location.href.indexOf('?') + 1).split('&');
for(var i = 0; i < hashes.length; i++)
{
	hash = hashes[i].split('=');
	vars.push(hash[0]);
	vars[hash[0]] = hash[1];
}
return vars;
}

function checkCustomFields(){
var error = [];
var exists_field = [];
if(jQuery(".custom_add_fields")){
	jQuery(".custom_add_fields").each(function(){
		
		var field_name = jQuery(this).attr('id');

		var name = field_name.replace('id_custom_fields_','');

		if(all_custom_fields.length > 0){
			var i =0;
			jQuery.each( all_custom_fields, function( key, value ){

				if(name == value.id || name == value.name){
					exists_field.push(name);
					return false;
				}

			});
		}else{
			jQuery('#id_custom_fields_'+name).remove();
		}

	});
}
if(exists_field.length > 0){
	jQuery(".custom_add_fields").each(function(){
		var field_name = jQuery(this).attr('id');
		var name = field_name.replace('id_custom_fields_','');
		if(jQuery.inArray(name,exists_field) == -1){
		   jQuery('#id_custom_fields_'+name).remove();
		}
	});
}else{
	jQuery('.custom_add_fields').remove();
}
}	

