function hmsToSecondsOnly(str) {

	var m = str.split('.');
	var f = '';
	if(m[1] != undefined && m[1] != ''){
		f = '.'+m[1];
	}
    var p = str.split(':'),
        s = 0, m = 1;

    while (p.length > 0) {
        s += m * parseInt(p.pop(), 10);
        m *= 60;
    }

    return s+f;
}


function fancyTimeFormat(duration) {
  // Hours, minutes and seconds
  const hrs = ~~(duration / 3600);
  const mins = ~~((duration % 3600) / 60);
  const secs = ~~duration % 60;
  
  var t = duration.toString().split('.');
  if(t[1] != undefined && t[1] != ''){
	var dur = duration.toString().split('.')[1];
	dur = '.'+dur.substring(0,3);
  }else{
	dur = '.000';
  }

  // Output like "1:01" or "4:03:59" or "123:03:59"
  let ret = "";

  if (hrs > 0) {
    ret += "" + hrs + ":" + (mins < 10 ? "0" : "");
  }

  ret += "" + mins + ":" + (secs < 10 ? "0" : "");
  ret += "" + secs;
  return ret+dur;
}

function generateBlobUrl(data){
	var newBlob = new Blob([data], { type: 'text/plain' });
	var url = URL.createObjectURL(newBlob);
	return url;
}

function updateTracks(url){

	let player = videojs('video_caption_player');

	var tracks = player.remoteTextTrackEls();

	for (let i = 0; i < tracks.length; i++) {
		var track = tracks[i];
		player.removeRemoteTextTrack(track);
	}

	player.addRemoteTextTrack({
				kind: 'subtitles',
				src: url,
				mode: 'showing'
	}, false);
}

function updateVideoCaption(obj,video,key_num,data){

	var data = [generateBlob()];
	//var data = ['WEBVTT\n\nkey-0\n00:00:00.000 --> 00:00:01.000\ntest\n\nkey-1\n00:00:01.100 --> 00:00:02.000\nYour caption text'];
	var blob = new Blob(data, { type: 'text/plain' });
	var reader = new FileReader();
	var value = obj.find('.caption-text').val();
	reader.addEventListener('loadend', () => {
	   var decoder = new TextDecoder();
  		var text = decoder.decode(reader.result);
  		let lines = text.split('\n');
		var newText = '';
		lines.forEach((line, index) => {
			if(key_num == line){
				var line_no = index+2;
				lines[line_no] = value+'\n';
				newText = lines.join('\n');

				// Create a new Blob object from the modified string
				var newBlob = new Blob([newText], { type: 'text/plain' });
				var url = URL.createObjectURL(newBlob);
				updateTracks(url);
				updateVideoTime(obj);
			}
		});
		
	});
	reader.readAsArrayBuffer(blob);
}

function updateVideoTime(obj){
	var time = obj.find('.caption-start-time').val();
	var sec = hmsToSecondsOnly('00:'+time);
	var video1 = document.getElementById("video_caption_player_html5_api");
	video1.currentTime = sec;
}

function sqbTimeToSecond(time){
	var timeString = time;
	var timeParts = timeString.split(":");
	var timeInSeconds = (+timeParts[0]) * 60 * 60 + (+timeParts[1]) * 60 + (+timeParts[2]);
	return timeInSeconds;
}

function refreshVideoSubtitle(obj){
	setTimeout(() => {
		var key = obj.attr('data-key');
		var video_obj = 'video_caption_player_html5_api';
		updateVideoTime(obj);
		//updateVideoCaption(obj,video_obj,key,'');
		var data = generateBlob();
		var newBlob = new Blob([data], { type: 'text/plain' });
		var url = URL.createObjectURL(newBlob);
		updateTracks(url);
	}, 300);
}

function repeaterAdvRules(rule_id){
	var firstElement = jQuery('.condition-rules-outer:first').clone(true).wrap('<div/>');
	firstElement.find('#selected_answers option').remove();
	var id = Math.random().toString(36).substring(2, 6+2);
	jQuery('.quiz-advance-rules-wraper .condition-rules-outer:last').after('<div class="condition-rules-outer" id="'+id+'">'+firstElement.html()+'</div>');
	jQuery('#'+id).find('.select2').remove();
	jQuery('#'+id).find('.sqb-select2').select2({ width: '100%' });
	return id;
}

function resetConditionRules(){
	jQuery('.condition-rules-outer').not(':first').remove();
	jQuery('.condition-rules-outer:first').find('.all_ques_div').val('0');
	jQuery('.condition-rules-outer:first').find('.select2').remove();
	jQuery('.condition-rules-outer:first').find('.sqb-select2').select2({ width: '100%' });
	jQuery('.condition-rules-outer').find('.all_resources_data:first').val('0').trigger('change');
}

function populateAdvRules(rule_id){
	// Remove All elements before edit except first one
	resetConditionRules();
	var myObject = JSON.parse(document.getElementById('json-sqb-advance-id-'+rule_id).textContent);
	var i = 0;
	var question_id = [];
	var quesAns = {};
	jQuery.each(myObject, function(key,valueObj){
		question_id.push(valueObj['question']);
		quesAns["q"+i+"_"+valueObj['question']] = valueObj['answer'];
		if(i == 0){
			jQuery('.condition-rules-outer:first').find('.all_ques_div').val(valueObj['question']);
			jQuery('.condition-rules-outer:first').find('.select2').remove();
			jQuery('.condition-rules-outer:first').find('.sqb-select2').select2({ width: '100%' });
		}else{
			var id = repeaterAdvRules(rule_id);
			jQuery('#'+id).find('.all_ques_div').val(valueObj['question']).trigger('change');
			jQuery('#'+id).find('.adv_exp').val(valueObj['expression']).attr('selected');
			jQuery('.condition-rules-outer').find('.sqb-select2').select2({ width: '100%' });
		}
		i++;
	});
    var ques_ids = question_id;
    
	SQBShowLoader();
    jQuery.post(ajaxurl, {
		action: 'sqbQuestionAnswerData',
		ques_ids: ques_ids,
	}, function(response) {
		SQBHideLoader();
		response = JSON.parse(response);
		var i = 0;
      jQuery.each(response, function(key,valueObj){
			var ques_id = ques_ids[i];
			var ans = quesAns["q"+i+"_"+ques_id];
			jQuery('.condition-rules-outer').find('.all_resources_data').eq(i).html(valueObj).val(ans).trigger('change');
			i++;
    });
	});
}

