var chatgpt_mprompt = 'I would like to create a personality quiz on the topic of [topic].%%LANG_MSG%%\n\nHelp me generate 10 engaging quiz titles. \n\Draw inspiration from the following examples:\nWhat type of (topic) is right for you?\nHow much do you know about (topic)\nWhich (topic) are you?\nWhat is your (topic) style?\nWhat kind of (topic) are you?\nWhat type of (topic) should you create?\n';
chatgpt_mprompt_lang = '\n\nResponse in %%QLANG%%\n\n';
jQuery(document).on('click','.chatgpt_show_mprompt', function(){
	var quiz_subject = jQuery('#chatgpt_quiz_subject_mprompt').val();
	mprompt_html = chatgpt_mprompt.replaceAll('[topic]',quiz_subject);

	var quiz_lang = jQuery('#chatgpt_quiz_lang').val();
	mprompt_html = mprompt_html.replaceAll('%%LANG_MSG%%','\n\nResponse in '+quiz_lang+'');

	jQuery('#chatgpt_title_prompt_mpopup .chatgpt_mprompt_format').html(mprompt_html);
});

jQuery(document).on('click','.chatgpt_quiztype_show_mprompt', function(){

	

	var quiz_subject = jQuery('#chatgpt_quiztype_subject_mprompt').val();
	var qt_mprompt_html = chatgpt_quiz_type_prompt.replaceAll('%%QUIZ_TOPIC%%',quiz_subject);

	var quiz_lang = jQuery('#chatgpt_quiz_lang').val();
	qt_mprompt_html = qt_mprompt_html.replaceAll('%%LANGUAGE%%',quiz_lang);

	var qtarget = jQuery('#chatgpt_target_subject_mprompt').val();
	qt_mprompt_html = qt_mprompt_html.replaceAll('%%QUIZ_TARGET%%',qtarget);

	var qtype = jQuery('input[name=chatgpt_quiz_type]:checked').val();
	qt_mprompt_html = qt_mprompt_html.replaceAll('%%TYPE%%',qtype);

	if(chatgpt_api_flow == 'manual'){
		qt_mprompt_html = qt_mprompt_html.replaceAll('%%QCOUNT%%',10);
		jQuery('#chatgpt_quiztype_prompt_mpopup .chatgpt_quiztype_mprompt_format').html(qt_mprompt_html);
		jQuery('.chatgpt_quiztype_title_prompt_code_hide_show').show();
	}else{
		qt_mprompt_html = qt_mprompt_html.replaceAll('%%QCOUNT%%',5);
		SQBShowLoader();
		jQuery.post(ajaxurl, 
			{
				action: 'sqb_ai_generate_quiz_ideas',
				prompt : qt_mprompt_html,
			}, function(response) {
				SQBHideLoader();
				var result = jQuery.parseJSON(response);
				if(result.status == 'ok') {
					jQuery('#chatgpt_quiztype_json').val(JSON.stringify(result.object));
					jQuery('.chatgpt_quiztype_generate').trigger('click');
				}else{
					if(result.code == 'invalid_api_key'){
						sqb_sweet_message('',"Please enter valid API Key.","");
					}else if(result.message != ''){
						sqb_sweet_message('',result.message,"");
					}
				}
		}).fail(function(jqXHR, textStatus, errorThrown) {
			SQBHideLoader();
            // Handle 504 error
            if (jqXHR.status === 504) {
                swal({
					title: "Gateway Timeout Error : 504",
					html: "Looks like the call to the OpenAI server is timing out.<br/><br/>Here are the options to try and resolve it:<br /> 1. Add this to your wp-config.php file:<br /> ini_set('max_execution_time', 180);<br /><br /> 2. If #1 does not work, set the maximum<br /> execution time in .htaccess.<br /><br /> php_value max_execution_time 180<br /><br /> If it still does not work, please contact <br /> your webhost's support team for assistance.",
					showCancelButton: true,
					showCloseButton: true,
					confirmButtonColor: "#DD6B55",
					confirmButtonText: "Retry",
					cancelButtonText: "Cancel",
					customClass: '',
					
				}).then((result) => {
					if (result.value) {
						jQuery('.chatgpt_quiztype_show_mprompt').trigger('click');
					}
				});
            } else {
                
            }
        });;
	}

	
});

jQuery(document).on('click','.chatgpt_quiztype_generate', function(){


	try {
		chatgpt_quiz_ideas = JSON.parse(jQuery('#chatgpt_quiztype_json').val());
	} catch (error) {
		swal('Invalid JSON format');
	}
	
	if(chatgpt_quiz_ideas.length > 0){
		jQuery('#chatgpt-quiztype-list').html('');
		jQuery.each(chatgpt_quiz_ideas, function(index, value) {
			if(value.title != undefined){
				var title = value.title;
			}else{
				var title = value;
			}

			var divTitle = '<div class="chatgpt-quiztype-title" data-content="'+title+'"><strong>Quiz Title: </strong>&nbsp;'+title+'</div>';
			var divDesc = '<div class="chatgpt-quiztype-desc" data-content="'+value.description+'"><strong>Description/Goal: </strong>&nbsp;'+value.description+'</div>';
			//var divPurpose = '<div class="chatgpt-quiztype-purpose"><strong>Purpose: </strong>&nbsp;'+value.purpose+'</div>';

			var divMain = divTitle + divDesc;

			jQuery('#chatgpt-quiztype-list').append('<li class="chatgpt-quiztype-item">' + divMain + '</li>');
		});

		jQuery('.chatgpt-quiztype-step1').hide();
		jQuery('.chatgpt-quiztype-step2').show();
		jQuery('.chatgpt-quiz-type-backto-prompt').show();
	}
});


